import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum FileType {
  FOLDER = 'folder',
  IMAGE = 'image',
  VIDEO = 'video',
  AUDIO = 'audio',
  DOCUMENT = 'document',
  ARCHIVE = 'archive',
  GENERIC = 'generic'
}

export interface FileItem {
  id: string;
  name: string;
  type: FileType;
  size: number | null; // null for directories
  lastModified: string;
  parentId: string | null;
  extension?: string;
}

export interface NavigationState {
  currentPath: string[]; // Array of IDs
  selectedIds: string[];
  viewMode: 'list' | 'grid';
}

import React from 'react';
import { 
  Folder, 
  FileText, 
  Image as ImageIcon, 
  Video, 
  Music, 
  Archive, 
