export const getFileIcon = (type: FileType, color: boolean = true) => {
  const props = { size: 20, className: color ? "" : "text-gray-500" };
  switch (type) {
    case FileType.FOLDER: return <Folder {...props} className={color ? "text-blue-500 fill-blue-500/20" : ""} />;
    case FileType.IMAGE: return <ImageIcon {...props} className={color ? "text-red-500" : ""} />;
    case FileType.VIDEO: return <Video {...props} className={color ? "text-red-600" : ""} />;
    case FileType.AUDIO: return <Music {...props} className={color ? "text-orange-500" : ""} />;
    case FileType.DOCUMENT: return <FileText {...props} className={color ? "text-blue-600" : ""} />;
    case FileType.ARCHIVE: return <Archive {...props} className={color ? "text-amber-600" : ""} />;
    default: return <File {...props} />;
  }
};

export const formatSize = (bytes: number | null): string => {
  if (bytes === null) return '--';
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

import { GoogleGenAI, Type } from "@google/genai";
import { FileItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export async function smartSearch(query: string, files: FileItem[]): Promise<string[]> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given a user query "${query}" and a list of files, return a JSON array of the file IDs that best match the user's intent. 
      Consider file types, names, and extensions.

      Files: ${JSON.stringify(files.map(f => ({ id: f.id, name: f.name, type: f.type, ext: f.extension })))}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Gemini Search Error:", error);
    // Fallback to basic string matching if AI fails
    return files
      .filter(f => f.name.toLowerCase().includes(query.toLowerCase()))
      .map(f => f.id);
  }
}

import React, { useState, useMemo, useCallback } from 'react';
