    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const currentFolderMetadata = useMemo(() => {
    return files.find(f => f.id === currentFolderId);
  }, [files, currentFolderId]);

  return (
    <div className="flex h-screen w-full bg-white select-none">
      {/* Sidebar */}
      <aside className="w-64 border-r border-gray-200 flex flex-col bg-[#f8f9fa]">
