                  <th className="font-medium p-3 pl-6 w-[50%]">Name</th>
                  <th className="font-medium p-3">Size</th>
                  <th className="font-medium p-3">Type</th>
                  <th className="font-medium p-3 pr-6">Date modified</th>
                </tr>
              </thead>
              <tbody>
                {filteredFiles.map((file) => (
                  <tr 
                    key={file.id}
                    onClick={(e) => toggleSelect(file.id, e)}
                    onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                    className={`hover:bg-gray-50 cursor-default transition-colors group ${
                      selectedIds.includes(file.id) ? 'bg-blue-50 text-blue-900' : ''
                    }`}
                  >
                    <td className="p-3 pl-6">
                      <div className="flex items-center gap-3">
                        {getFileIcon(file.type)}
                        <span className="truncate max-w-xs">{file.name}</span>
                      </div>
                    </td>
                    <td className="p-3 text-gray-500 group-hover:text-gray-900">
                      {formatSize(file.size)}
                    </td>
                    <td className="p-3 text-gray-500 group-hover:text-gray-900">
                      {file.type === FileType.FOLDER ? 'Folder' : (file.extension?.toUpperCase() || 'File')}
                    </td>
                    <td className="p-3 pr-6 text-gray-500 group-hover:text-gray-900">
                      {file.lastModified}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 p-4">
              {filteredFiles.map((file) => (
                <div 
                  key={file.id}
                  onClick={(e) => toggleSelect(file.id, e)}
                  onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                  className={`flex flex-col items-center p-4 rounded-xl border transition-all ${
                    selectedIds.includes(file.id) 
                    ? 'bg-blue-50 border-blue-200 ring-2 ring-blue-500 ring-opacity-50 shadow-sm' 
                    : 'bg-white border-transparent hover:bg-gray-50 hover:border-gray-200'
                  }`}
                >
                  <div className="mb-3">
                    {React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: 48 })}
                  </div>
                  <span className="text-center text-xs font-medium truncate w-full px-2">
                    {file.name}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Footer (Simplified from prompt) */}
      <footer className="fixed bottom-0 right-0 left-0 bg-white border-t border-gray-200 h-16 flex items-center justify-between px-6 z-20">
         <div className="flex gap-2">
            <button className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition-colors shadow-sm">
               <Plus size={18} />
               <span className="text-sm font-medium">New</span>
            </button>
         </div>
         <div className="flex gap-4">
            <button className="text-sm text-gray-500 hover:text-gray-800">Cancel</button>
            <button className="px-6 py-2 bg-blue-50 text-blue-700 border border-blue-200 rounded-full text-sm font-medium hover:bg-blue-100">
              Open
            </button>
         </div>
      </footer>
    </div>
  );
}

