import { GoogleGenAI, Type } from "@google/genai";
import { FileItem } from "../types";

// Fix: Strictly follow SDK initialization rules - use process.env.API_KEY directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function smartSearch(query: string, files: FileItem[]): Promise<string[]> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given a user query "${query}" and a list of files, return a JSON array of the file IDs that best match the user's intent. 
      Consider file types, names, and extensions.

      Files: ${JSON.stringify(files.map(f => ({ id: f.id, name: f.name, type: f.type, ext: f.extension })))}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING
          }
        }
      }
    });

    // Fix: Access .text property directly (it's a getter, not a method).
    const text = response.text || "[]";
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Search Error:", error);
    // Fallback to basic string matching if AI fails
    return files
      .filter(f => f.name.toLowerCase().includes(query.toLowerCase()))
      .map(f => f.id);
  }
}

