};

export function str(id: keyof typeof DATA): string {
  return DATA[id] || id;
}

export function strf(id: keyof typeof DATA, ...args: any[]): string {
  let template = str(id);
  args.forEach((arg, i) => {
    template = template.replace(`$${i + 1}`, String(arg));
  });
  return template;
}

export enum FileType {
  FOLDER = 'folder',
  IMAGE = 'image',
  VIDEO = 'video',
  AUDIO = 'audio',
  DOCUMENT = 'document',
  ARCHIVE = 'archive',
  GENERIC = 'generic'
}

export interface FileItem {
  id: string;
  name: string;
  type: FileType;
  size: number | null;
  lastModified: string;
  parentId: string | null;
  extension?: string;
  // AI Knowledge Base fields
  content?: string; // Text content or Base64
  aiSummary?: string;
  aiKeywords?: string[];
  isIndexing?: boolean;
}

export interface NavigationState {
  currentPath: string[];
