}

import { GoogleGenAI, Type } from "@google/genai";
import { FileItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a semantic summary and keywords for a file to build the knowledge base.
 */
export async function indexFile(file: FileItem): Promise<{ summary: string; keywords: string[] }> {
  try {
    const prompt = `Analyze this file and create a semantic index for a knowledge base.
    File Name: ${file.name}
    Type: ${file.type}
    ${file.content ? `Content Preview: ${file.content.substring(0, 2000)}` : "No content available (binary file)."}

    Return a JSON object with:
    1. "summary": A concise 1-sentence summary of what this file is about.
    2. "keywords": An array of 5 key topics or entities found in the file.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            keywords: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    return JSON.parse(response.text || '{"summary": "No summary available", "keywords": []}');
  } catch (error) {
    console.error("Indexing error:", error);
    return { summary: "Error indexing file", keywords: [] };
  }
}

/**
 * Queries the entire knowledge base.
 */
export async function queryKnowledgeBase(query: string, files: FileItem[]): Promise<string> {
  const context = files
    .filter(f => f.aiSummary)
    .map(f => `[File: ${f.name}] Summary: ${f.aiSummary} Keywords: ${f.aiKeywords?.join(", ")}`)
    .join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `You are the brain of a file system. Answer the user's question based ONLY on the provided file summaries. 
    If you don't know, say you don't have files related to that.

    File Context:
    ${context}

    Question: ${query}`,
  });

  return response.text || "I couldn't process that request.";
}

export async function smartSearch(query: string, files: FileItem[]): Promise<string[]> {
  try {
    const fileList = files.map(f => ({ 
      id: f.id, 
      name: f.name, 
      summary: f.aiSummary, 
      keywords: f.aiKeywords 
    }));

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User is searching for: "${query}". 
      Analyze the semantic meaning of the query and return the IDs of the most relevant files.
      Files: ${JSON.stringify(fileList)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    return files
      .filter(f => f.name.toLowerCase().includes(query.toLowerCase()))
      .map(f => f.id);
  }
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
