export default function App() {
  const [files, setFiles] = useState<FileItem[]>(MOCK_FILES);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  const filteredFiles = useMemo(() => {
    if (aiResults) return files.filter(f => aiResults.includes(f.id));
    if (searchQuery && !isSearching) {
      return files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return files.filter(f => f.parentId === currentFolderId);
  }, [files, currentFolderId, searchQuery, aiResults, isSearching]);

  // Handle indexing new files
  const indexNewFile = async (newFile: FileItem) => {
    setFiles(prev => prev.map(f => f.id === newFile.id ? { ...f, isIndexing: true } : f));
    const result = await indexFile(newFile);
    setFiles(prev => prev.map(f => f.id === newFile.id ? { 
      ...f, 
      aiSummary: result.summary, 
      aiKeywords: result.keywords,
      isIndexing: false 
    } : f));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;

    Array.from(loadedFiles).forEach(file => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          content: file.type.startsWith('text/') ? content : undefined,
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        indexNewFile(newFile);
      };
      if (file.type.startsWith('text/')) {
        reader.readAsText(file);
      } else {
        reader.readAsDataURL(file);
      }
    });
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;

    const userMsg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsBrainThinking(true);

    const aiResponse = await queryKnowledgeBase(userMsg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: aiResponse }]);
    setIsBrainThinking(false);
  };

  const handleFolderClick = (id: string) => {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
    setSearchQuery('');
  };

  const handleBack = () => {
    if (path.length > 0) setPath(path.slice(0, -1));
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const navSections = useMemo(() => ({
    top: NAV_ITEMS.filter(i => i.section === 'top'),
    my_files: NAV_ITEMS.filter(i => i.section === 'my_files'),
    google_drive: NAV_ITEMS.filter(i => i.section === 'google_drive'),
    trash: NAV_ITEMS.filter(i => i.section === 'trash'),
  }), []);

