            {navSections.top.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
