                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="px-4 py-3 bg-indigo-50 rounded-xl mx-2 border border-indigo-100 group cursor-pointer hover:bg-indigo-100 transition-colors"
