            <div className="relative group">
              <div className="flex items-center bg-[#f1f3f4] rounded-xl focus-within:bg-white focus-within:shadow-md transition-all px-4 py-2 w-64 lg:w-96">
                <Search size={18} className="text-[#5f6368] mr-2" />
                <input 
                  type="text"
                  placeholder="Semantic Search (AI-Powered)..."
                  className="bg-transparent border-none outline-none text-sm w-full text-[#3c4043]"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
                />
                {searchQuery && (
                  <button onClick={() => {setSearchQuery(''); setAiResults(null);}} className="p-1 hover:bg-[#e8eaed] rounded-full">
                    <X size={14} className="text-[#5f6368]" />
                  </button>
                )}
              </div>
            </div>

            <button onClick={() => setIsBrainOpen(!isBrainOpen)} className={`p-2 rounded-full transition-colors ${isBrainOpen ? 'bg-indigo-100 text-indigo-700' : 'hover:bg-[#e8eaed] text-[#5f6368]'}`}>
              <Brain size={20} />
            </button>
            <button className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]">
              <RotateCw size={20} />
            </button>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : 'list')}
              className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]"
            >
              {viewMode === 'list' ? <LayoutGrid size={20} /> : <List size={20} />}
            </button>
          </div>
        </header>

        {/* AI Selected File Insight */}
        {selectedFile && (
          <div className="px-6 py-4 border-b border-indigo-50 bg-indigo-50/30 animate-in slide-in-from-top duration-300">
            <div className="flex items-start gap-4">
              <div className="p-2 bg-white rounded-lg shadow-sm">
                <Sparkles size={16} className="text-indigo-600" />
              </div>
              <div className="flex-1">
                <div className="text-xs font-bold text-indigo-700 mb-1 flex items-center gap-2 uppercase tracking-wide">
                  Gemini Insight
                  {selectedFile.isIndexing && <Loader2 size={12} className="animate-spin" />}
                </div>
                <p className="text-sm text-[#3c4043] leading-relaxed">
                  {selectedFile.isIndexing ? "Analyzing file content and extracting metadata..." : (selectedFile.aiSummary || "No AI insight available for this file yet.")}
                </p>
                {selectedFile.aiKeywords && (
                  <div className="flex flex-wrap gap-2 mt-2">
                    {selectedFile.aiKeywords.map(k => (
                      <span key={k} className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-bold">#{k}</span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Action Bar (When files selected) */}
        {selectedIds.length > 0 && (
          <div className="h-12 bg-[#e8f0fe] border-b border-[#d2e3fc] flex items-center px-6 justify-between animate-in slide-in-from-top duration-200">
            <div className="flex items-center gap-4">
              <button onClick={() => setSelectedIds([])} className="text-[#1a73e8] hover:bg-[#d2e3fc] p-1 rounded-full transition-colors">
                <X size={18} />
              </button>
              <span className="text-[#185abc] text-sm font-medium">{selectedIds.length} item(s) selected</span>
            </div>
            <div className="flex items-center gap-6">
              <button className="text-sm font-semibold text-[#1a73e8] hover:underline">Share</button>
              <button className="text-sm font-semibold text-[#1a73e8] hover:underline">Download</button>
              <button className="text-sm font-semibold text-[#d93025] hover:underline">{str('DELETE_BUTTON_LABEL')}</button>
            </div>
          </div>
        )}

        {/* AI Search Banner */}
        {aiResults && (
           <div className="px-6 py-2.5 bg-gradient-to-r from-[#e8f0fe] to-[#f3e8ff] border-b border-blue-100 flex items-center justify-between">
             <div className="flex items-center gap-2 text-sm text-[#185abc] font-medium italic">
               <Sparkles size={14} />
               <span>AI Semantic Filter: "{searchQuery}"</span>
             </div>
             <button onClick={() => {setAiResults(null); setSearchQuery('');}} className="text-[10px] bg-white text-blue-600 px-3 py-1 rounded-full font-bold hover:bg-white shadow-sm border border-blue-100">CLEAR</button>
           </div>
        )}

        {/* File Browser Body */}
        <div className="flex-1 overflow-auto bg-white relative">
          {isSearching ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-500 gap-4">
              <div className="w-12 h-12 border-[3px] border-[#e8f0fe] border-t-[#1a73e8] rounded-full animate-spin"></div>
              <p className="text-sm font-medium">Gemini is finding matches...</p>
            </div>
          ) : filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-[#9aa0a6]">
              <div className="w-24 h-24 mb-4 bg-[#f8f9fa] rounded-full flex items-center justify-center shadow-inner">
                <Folder size={48} className="text-[#e8eaed]" />
              </div>
              <p className="text-lg font-medium">This folder is empty</p>
            </div>
          ) : viewMode === 'list' ? (
            <table className="w-full border-collapse text-[13px]">
              <thead>
                <tr className="text-left text-[#5f6368] border-b border-gray-100 sticky top-0 bg-white z-10">
                  <th className="font-semibold p-3 pl-6 w-[45%]">{str('NAME_COLUMN_LABEL')}</th>
                  <th className="font-semibold p-3 w-[15%]">{str('SIZE_COLUMN_LABEL')}</th>
                  <th className="font-semibold p-3 w-[20%]">Knowledge Base Status</th>
                  <th className="font-semibold p-3 pr-6 w-[20%]">{str('DATE_COLUMN_LABEL')}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {filteredFiles.map((file) => (
                  <tr 
                    key={file.id}
                    onClick={(e) => toggleSelect(file.id, e)}
                    onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                    className={`hover:bg-[#f8f9fa] cursor-default transition-colors group ${
                      selectedIds.includes(file.id) ? 'bg-[#e8f0fe] text-[#185abc]' : 'text-[#3c4043]'
                    }`}
                  >
                    <td className="p-3 pl-6">
                      <div className="flex items-center gap-3">
                        <div className="transition-transform group-hover:scale-110 duration-200">
                          {getFileIcon(file.type)}
                        </div>
                        <span className="truncate max-w-xs font-medium">{file.name}</span>
                      </div>
                    </td>
                    <td className="p-3 text-[#5f6368]">
                      {formatSize(file.size)}
                    </td>
                    <td className="p-3">
                      {file.isIndexing ? (
                        <span className="flex items-center gap-2 text-blue-500 font-medium">
                          <Loader2 size={12} className="animate-spin" /> Indexing...
                        </span>
                      ) : file.aiSummary ? (
                        <span className="text-emerald-600 flex items-center gap-1.5 font-medium">
                          <Sparkles size={12} /> Indexed
                        </span>
                      ) : <span className="text-gray-400">-</span>}
                    </td>
                    <td className="p-3 pr-6 text-[#5f6368]">
                      {file.lastModified}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6 p-6">
              {filteredFiles.map((file) => (
                <div 
                  key={file.id}
                  onClick={(e) => toggleSelect(file.id, e)}
                  onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                  className={`flex flex-col items-center p-4 rounded-2xl border transition-all relative ${
                    selectedIds.includes(file.id) 
                    ? 'bg-[#e8f0fe] border-[#1a73e8] ring-1 ring-[#1a73e8] shadow-md scale-105' 
                    : 'bg-white border-transparent hover:bg-[#f1f3f4] hover:border-gray-200'
                  }`}
                >
                  {file.aiSummary && !file.isIndexing && (
                    <div className="absolute top-2 right-2 text-emerald-500">
                      <Sparkles size={14} />
                    </div>
                  )}
                  {file.isIndexing && (
                    <div className="absolute top-2 right-2 text-blue-500 animate-spin">
                      <Loader2 size={14} />
                    </div>
                  )}
                  <div className="mb-4">
                    {React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: 56 })}
                  </div>
                  <span className="text-center text-xs font-semibold truncate w-full px-2 text-[#3c4043]">
                    {file.name}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="bg-white border-t border-gray-200 h-16 flex items-center justify-between px-6 z-20 shrink-0">
           <div className="flex gap-2">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 px-6 py-2.5 bg-[#1a73e8] text-white rounded-full hover:bg-blue-700 transition-all shadow-md active:scale-95 font-medium text-sm"
              >
                 <FileUp size={18} />
                 <span>Upload & Index</span>
              </button>
           </div>
           <div className="flex gap-3">
              <button className="text-sm font-semibold text-[#5f6368] hover:bg-[#f1f3f4] px-4 py-2 rounded-full transition-colors">{str('CANCEL_LABEL')}</button>
              <button className={`px-8 py-2 rounded-full text-sm font-bold transition-all ${selectedIds.length > 0 ? 'bg-[#1a73e8] text-white shadow-md' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}>
                {str('OPEN_LABEL')}
              </button>
           </div>
        </footer>
      </main>

      {/* System Brain Slide-out Panel */}
      <div className={`fixed right-0 top-0 h-full w-96 bg-[#f8f9fa] border-l border-gray-200 shadow-2xl transition-transform duration-500 z-50 flex flex-col ${isBrainOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 border-b border-gray-200 bg-white flex items-center justify-between">
          <div className="flex items-center gap-3 text-indigo-700 font-bold">
            <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center">
              <Brain size={24} />
            </div>
            <div>
              <div className="text-sm">SYSTEM BRAIN</div>
              <div className="text-[10px] text-gray-500 font-normal uppercase tracking-widest">Knowledge Base Chat</div>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-2 hover:bg-gray-100 rounded-full text-gray-400">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          {brainChat.length === 0 && (
            <div className="text-center py-12">
              <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-indigo-200">
                <MessageSquare size={32} />
              </div>
              <p className="text-sm text-gray-500">Ask a question about the files you've indexed in this session.</p>
              <div className="mt-4 flex flex-wrap justify-center gap-2">
                {['Summarize my documents', 'Find images about vacation', 'Check latest modified files'].map(hint => (
                  <button key={hint} onClick={() => setBrainInput(hint)} className="text-[10px] bg-white border border-gray-200 px-3 py-1.5 rounded-full text-gray-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all font-medium">
                    "{hint}"
                  </button>
                ))}
              </div>
            </div>
          )}
          {brainChat.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white border border-gray-200 text-[#3c4043] rounded-tl-none shadow-sm'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isBrainThinking && (
            <div className="flex justify-start">
              <div className="bg-white border border-gray-200 px-4 py-3 rounded-2xl rounded-tl-none shadow-sm">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-4 bg-white border-t border-gray-200">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Ask anything..."
              className="w-full bg-[#f1f3f4] border-none outline-none py-3 pl-4 pr-12 rounded-xl text-sm"
              value={brainInput}
              onChange={(e) => setBrainInput(e.target.value)}
            />
            <button className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
              <Sparkles size={16} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Search, 
  RotateCw, 
  LayoutGrid, 
  List, 
  MoreVertical, 
  ChevronRight,
  ArrowLeft,
  X,
  Plus,
  Folder,
  Cloud,
  Brain,
  MessageSquare,
  FileUp,
  Sparkles,
  Loader2
} from 'lucide-react';
import { FileItem, FileType } from './types';
import { MOCK_FILES, NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase } from './services/geminiService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>(MOCK_FILES);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  const filteredFiles = useMemo(() => {
    if (aiResults) return files.filter(f => aiResults.includes(f.id));
    if (searchQuery && !isSearching) {
      return files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return files.filter(f => f.parentId === currentFolderId);
  }, [files, currentFolderId, searchQuery, aiResults, isSearching]);

  // Handle indexing new files
  const indexNewFile = async (newFile: FileItem) => {
    setFiles(prev => prev.map(f => f.id === newFile.id ? { ...f, isIndexing: true } : f));
    const result = await indexFile(newFile);
    setFiles(prev => prev.map(f => f.id === newFile.id ? { 
      ...f, 
      aiSummary: result.summary, 
      aiKeywords: result.keywords,
      isIndexing: false 
    } : f));
  };

  // Fixed 'unknown' type errors by adding explicit type annotation for file objects
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;

    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          content: file.type.startsWith('text/') ? content : undefined,
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        indexNewFile(newFile);
      };
      if (file.type.startsWith('text/')) {
        reader.readAsText(file);
      } else {
        reader.readAsDataURL(file);
      }
    });
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;

    const userMsg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsBrainThinking(true);

    const aiResponse = await queryKnowledgeBase(userMsg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: aiResponse }]);
    setIsBrainThinking(false);
  };

  const handleFolderClick = (id: string) => {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
    setSearchQuery('');
  };

  const handleBack = () => {
    if (path.length > 0) setPath(path.slice(0, -1));
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const navSections = useMemo(() => ({
    top: NAV_ITEMS.filter(i => i.section === 'top'),
    my_files: NAV_ITEMS.filter(i => i.section === 'my_files'),
    google_drive: NAV_ITEMS.filter(i => i.section === 'google_drive'),
    trash: NAV_ITEMS.filter(i => i.section === 'trash'),
  }), []);

  const selectedFile = useMemo(() => 
    selectedIds.length === 1 ? files.find(f => f.id === selectedIds[0]) : null
  , [selectedIds, files]);

  return (
    <div className="flex h-screen w-full bg-white select-none overflow-hidden relative">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Sidebar */}
      <aside className="w-64 border-r border-gray-200 flex flex-col bg-[#f8f9fa] z-10 shrink-0">
        <div className="p-4 mb-2">
          <div className="flex items-center gap-2 px-3 py-2 text-blue-600 font-medium text-lg tracking-tight">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-sm">
              <Plus size={20} />
            </div>
            <span className="font-semibold text-[#1a73e8]">{str('FILEMANAGER_APP_NAME')}</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-2 space-y-4">
          <div className="space-y-1">
            {navSections.top.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8] font-medium' : 'text-[#5f6368] hover:bg-[#e8eaed]'
                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="space-y-1">
            <div className="px-4 text-[11px] font-bold text-[#5f6368] uppercase tracking-wider mb-1">
              {str('MY_FILES_ROOT_LABEL')}
            </div>
            {navSections.my_files.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8] font-medium' : 'text-[#5f6368] hover:bg-[#e8eaed]'
                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="px-4 py-3 bg-indigo-50 rounded-xl mx-2 border border-indigo-100 group cursor-pointer hover:bg-indigo-100 transition-colors"
               onClick={() => setIsBrainOpen(true)}>
            <div className="flex items-center gap-2 text-indigo-700 font-bold text-xs mb-1">
              <Brain size={14} className="animate-pulse" />
              SYSTEM BRAIN
            </div>
            <div className="text-[10px] text-indigo-600 font-medium">
              Ask about your {files.length} indexed files.
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-gray-100">
          <div className="flex justify-between text-[11px] text-[#5f6368] mb-1.5 font-medium">
            <span>Storage (Session)</span>
          </div>
          <div className="w-full h-1 bg-[#e8eaed] rounded-full overflow-hidden">
            <div className="h-full bg-blue-500 rounded-full" style={{ width: '15%' }}></div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        <header className="h-16 flex items-center justify-between px-6 border-b border-gray-100">
          <div className="flex items-center gap-3 min-w-0">
            {path.length > 0 && (
              <button onClick={handleBack} className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-1 overflow-hidden text-sm">
              <span className="text-[#5f6368] whitespace-nowrap">{NAV_ITEMS.find(n => n.id === currentNav)?.label}</span>
              {path.map((folderId, idx) => {
                const folder = files.find(f => f.id === folderId);
                return (
                  <React.Fragment key={folderId}>
                    <ChevronRight size={14} className="text-[#9aa0a6] flex-shrink-0" />
                    <span className={`whitespace-nowrap ${idx === path.length - 1 ? 'font-medium text-[#202124]' : 'text-[#5f6368] hover:underline cursor-pointer'}`}>
                      {folder?.name}
                    </span>
                  </React.Fragment>
                );
              })}
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="relative group">
              <div className="flex items-center bg-[#f1f3f4] rounded-xl focus-within:bg-white focus-within:shadow-md transition-all px-4 py-2 w-64 lg:w-96">
                <Search size={18} className="text-[#5f6368] mr-2" />
                <input 
                  type="text"
                  placeholder="Semantic Search (AI-Powered)..."
                  className="bg-transparent border-none outline-none text-sm w-full text-[#3c4043]"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
                />
                {searchQuery && (
                  <button onClick={() => {setSearchQuery(''); setAiResults(null);}} className="p-1 hover:bg-[#e8eaed] rounded-full">
                    <X size={14} className="text-[#5f6368]" />
                  </button>
                )}
              </div>
            </div>

            <button onClick={() => setIsBrainOpen(!isBrainOpen)} className={`p-2 rounded-full transition-colors ${isBrainOpen ? 'bg-indigo-100 text-indigo-700' : 'hover:bg-[#e8eaed] text-[#5f6368]'}`}>
              <Brain size={20} />
            </button>
            <button className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]">
              <RotateCw size={20} />
            </button>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : 'list')}
