                  <div className="flex flex-wrap gap-2 mt-2">
                    {selectedFile.aiKeywords.map(k => (
                      <span key={k} className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-bold">#{k}</span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Action Bar (When files selected) */}
        {selectedIds.length > 0 && (
          <div className="h-12 bg-[#e8f0fe] border-b border-[#d2e3fc] flex items-center px-6 justify-between animate-in slide-in-from-top duration-200">
            <div className="flex items-center gap-4">
              <button onClick={() => setSelectedIds([])} className="text-[#1a73e8] hover:bg-[#d2e3fc] p-1 rounded-full transition-colors">
                <X size={18} />
