        {/* AI Search Banner */}
        {aiResults && (
           <div className="px-6 py-2.5 bg-gradient-to-r from-[#e8f0fe] to-[#f3e8ff] border-b border-blue-100 flex items-center justify-between">
             <div className="flex items-center gap-2 text-sm text-[#185abc] font-medium italic">
               <Sparkles size={14} />
