             </div>
             <button onClick={() => {setAiResults(null); setSearchQuery('');}} className="text-[10px] bg-white text-blue-600 px-3 py-1 rounded-full font-bold hover:bg-white shadow-sm border border-blue-100">CLEAR</button>
           </div>
        )}

        {/* File Browser Body */}
        <div className="flex-1 overflow-auto bg-white relative">
          {isSearching ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-500 gap-4">
              <div className="w-12 h-12 border-[3px] border-[#e8f0fe] border-t-[#1a73e8] rounded-full animate-spin"></div>
              <p className="text-sm font-medium">Gemini is finding matches...</p>
            </div>
          ) : filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-[#9aa0a6]">
              <div className="w-24 h-24 mb-4 bg-[#f8f9fa] rounded-full flex items-center justify-center shadow-inner">
                <Folder size={48} className="text-[#e8eaed]" />
