                  <th className="font-semibold p-3 w-[15%]">{str('SIZE_COLUMN_LABEL')}</th>
                  <th className="font-semibold p-3 w-[20%]">Knowledge Base Status</th>
                  <th className="font-semibold p-3 pr-6 w-[20%]">{str('DATE_COLUMN_LABEL')}</th>
