                {filteredFiles.map((file) => (
                  <tr 
                    key={file.id}
                    onClick={(e) => toggleSelect(file.id, e)}
                    onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                    className={`hover:bg-[#f8f9fa] cursor-default transition-colors group ${
