            </table>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6 p-6">
              {filteredFiles.map((file) => (
                <div 
                  key={file.id}
                  onClick={(e) => toggleSelect(file.id, e)}
                  onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                  className={`flex flex-col items-center p-4 rounded-2xl border transition-all relative ${
                    selectedIds.includes(file.id) 
                    ? 'bg-[#e8f0fe] border-[#1a73e8] ring-1 ring-[#1a73e8] shadow-md scale-105' 
                    : 'bg-white border-transparent hover:bg-[#f1f3f4] hover:border-gray-200'
                  }`}
                >
                  {file.aiSummary && !file.isIndexing && (
                    <div className="absolute top-2 right-2 text-emerald-500">
                      <Sparkles size={14} />
                    </div>
                  )}
                  {file.isIndexing && (
                    <div className="absolute top-2 right-2 text-blue-500 animate-spin">
                      <Loader2 size={14} />
                    </div>
                  )}
                  <div className="mb-4">
                    {React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: 56 })}
                  </div>
                  <span className="text-center text-xs font-semibold truncate w-full px-2 text-[#3c4043]">
                    {file.name}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="bg-white border-t border-gray-200 h-16 flex items-center justify-between px-6 z-20 shrink-0">
           <div className="flex gap-2">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 px-6 py-2.5 bg-[#1a73e8] text-white rounded-full hover:bg-blue-700 transition-all shadow-md active:scale-95 font-medium text-sm"
              >
                 <FileUp size={18} />
                 <span>Upload & Index</span>
              </button>
           </div>
           <div className="flex gap-3">
              <button className="text-sm font-semibold text-[#5f6368] hover:bg-[#f1f3f4] px-4 py-2 rounded-full transition-colors">{str('CANCEL_LABEL')}</button>
              <button className={`px-8 py-2 rounded-full text-sm font-bold transition-all ${selectedIds.length > 0 ? 'bg-[#1a73e8] text-white shadow-md' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}>
                {str('OPEN_LABEL')}
              </button>
           </div>
        </footer>
      </main>

      {/* System Brain Slide-out Panel */}
      <div className={`fixed right-0 top-0 h-full w-96 bg-[#f8f9fa] border-l border-gray-200 shadow-2xl transition-transform duration-500 z-50 flex flex-col ${isBrainOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 border-b border-gray-200 bg-white flex items-center justify-between">
          <div className="flex items-center gap-3 text-indigo-700 font-bold">
            <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center">
              <Brain size={24} />
            </div>
            <div>
              <div className="text-sm">SYSTEM BRAIN</div>
              <div className="text-[10px] text-gray-500 font-normal uppercase tracking-widest">Knowledge Base Chat</div>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-2 hover:bg-gray-100 rounded-full text-gray-400">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          {brainChat.length === 0 && (
            <div className="text-center py-12">
              <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-indigo-200">
                <MessageSquare size={32} />
              </div>
              <p className="text-sm text-gray-500">Ask a question about the files you've indexed in this session.</p>
              <div className="mt-4 flex flex-wrap justify-center gap-2">
                {['Summarize my documents', 'Find images about vacation', 'Check latest modified files'].map(hint => (
                  <button key={hint} onClick={() => setBrainInput(hint)} className="text-[10px] bg-white border border-gray-200 px-3 py-1.5 rounded-full text-gray-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all font-medium">
                    "{hint}"
                  </button>
                ))}
              </div>
            </div>
          )}
          {brainChat.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white border border-gray-200 text-[#3c4043] rounded-tl-none shadow-sm'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isBrainThinking && (
            <div className="flex justify-start">
              <div className="bg-white border border-gray-200 px-4 py-3 rounded-2xl rounded-tl-none shadow-sm">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-4 bg-white border-t border-gray-200">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Ask anything..."
              className="w-full bg-[#f1f3f4] border-none outline-none py-3 pl-4 pr-12 rounded-xl text-sm"
              value={brainInput}
              onChange={(e) => setBrainInput(e.target.value)}
            />
            <button className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
              <Sparkles size={16} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import React from 'react';
import { 
  Folder, 
  FileText, 
  Image as ImageIcon, 
  Video, 
  Music, 
  Archive, 
  File,
  Clock,
  Star,
  Trash2,
  HardDrive,
  Cloud,
  Cpu,
  Smartphone
} from 'lucide-react';
import { FileType } from './types';
import { str } from './lib/loadTimeData';

export const ICON_TYPES = {
  ANDROID_FILES: "android_files",
  ARCHIVE: "archive",
  AUDIO: "audio",
  CROSTINI: "crostini",
  DOWNLOADS: "downloads",
  DRIVE: "drive",
  FOLDER: "folder",
  GENERIC: "generic",
  IMAGE: "image",
  MY_FILES: "my_files",
  RECENT: "recent",
  STAR: "star",
  TRASH: "trash",
  VIDEO: "video",
  CLOUD: "cloud"
};

export const NAV_ITEMS = [
  { id: 'recent', label: str('RECENT_ROOT_LABEL'), icon: <Clock size={18} />, section: 'top' },
  { id: 'starred', label: 'Starred', icon: <Star size={18} />, section: 'top' },
  { id: 'root', label: str('MY_FILES_ROOT_LABEL'), icon: <HardDrive size={18} />, section: 'my_files' },
  { id: 'drive', label: str('DRIVE_DIRECTORY_LABEL'), icon: <Cloud size={18} />, section: 'google_drive' },
  { id: 'linux', label: str('LINUX_FILES_ROOT_LABEL'), icon: <Cpu size={18} />, section: 'my_files' },
  { id: 'android', label: str('ANDROID_FILES_ROOT_LABEL'), icon: <Smartphone size={18} />, section: 'my_files' },
  { id: 'trash', label: str('TRASH_ROOT_LABEL'), icon: <Trash2 size={18} />, section: 'trash' },
];

export const getFileIcon = (type: FileType, color: boolean = true) => {
  const props = { size: 20, className: color ? "" : "text-gray-500" };
  switch (type) {
    case FileType.FOLDER: return <Folder {...props} className={color ? "text-blue-500 fill-blue-500/10" : ""} />;
    case FileType.IMAGE: return <ImageIcon {...props} className={color ? "text-red-400" : ""} />;
    case FileType.VIDEO: return <Video {...props} className={color ? "text-red-500" : ""} />;
    case FileType.AUDIO: return <Music {...props} className={color ? "text-orange-400" : ""} />;
    case FileType.DOCUMENT: return <FileText {...props} className={color ? "text-blue-400" : ""} />;
    case FileType.ARCHIVE: return <Archive {...props} className={color ? "text-amber-500" : ""} />;
    default: return <File {...props} />;
  }
};

export const formatSize = (bytes: number | null): string => {
  if (bytes === null) return '--';
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  RotateCw, 
  LayoutGrid, 
  List, 
  MoreVertical, 
  ChevronRight,
  ArrowLeft,
  X,
  Plus,
  Folder,
  Brain,
  MessageSquare,
  FileUp,
  Sparkles,
  Loader2
} from 'lucide-react';
import { FileItem, FileType } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase } from './services/geminiService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  const filteredFiles = useMemo(() => {
    if (aiResults) return files.filter(f => aiResults.includes(f.id));
    if (searchQuery && !isSearching) {
      return files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return files.filter(f => f.parentId === currentFolderId);
  }, [files, currentFolderId, searchQuery, aiResults, isSearching]);

  // Recursive delete helper
  const handleDelete = () => {
    const getDescendants = (parentId: string, allFiles: FileItem[]): string[] => {
      let descendants: string[] = [];
      const children = allFiles.filter(f => f.parentId === parentId);
      children.forEach(child => {
        descendants.push(child.id);
        if (child.type === FileType.FOLDER) {
          descendants = [...descendants, ...getDescendants(child.id, allFiles)];
        }
      });
      return descendants;
    };

    let allIdsToRemove = [...selectedIds];
    selectedIds.forEach(id => {
      const file = files.find(f => f.id === id);
      if (file?.type === FileType.FOLDER) {
        allIdsToRemove = [...allIdsToRemove, ...getDescendants(id, files)];
      }
    });

    const finalDeleteSet = new Set(allIdsToRemove);
    setFiles(prev => prev.filter(f => !finalDeleteSet.has(f.id)));
    setSelectedIds([]);
  };

  const handleShare = async () => {
    if (selectedIds.length === 0) return;
    const file = files.find(f => f.id === selectedIds[0]);
    if (!file) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: file.name,
          text: `AI Knowledge Base Entry: ${file.name}\n${file.aiSummary || 'No summary available'}`,
          url: window.location.href,
        });
      } catch (err) {
        console.error("Share failed:", err);
      }
    } else {
      navigator.clipboard.writeText(file.name);
      alert(`Web Share API not supported. Copied name "${file.name}" to clipboard.`);
    }
  };

  const indexNewFile = async (newFile: FileItem) => {
    setFiles(prev => prev.map(f => f.id === newFile.id ? { ...f, isIndexing: true } : f));
    const result = await indexFile(newFile);
    setFiles(prev => prev.map(f => f.id === newFile.id ? { 
      ...f, 
      aiSummary: result.summary, 
      aiKeywords: result.keywords,
      isIndexing: false 
    } : f));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;

    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          content: file.type.startsWith('text/') ? content : undefined,
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        indexNewFile(newFile);
      };
      if (file.type.startsWith('text/')) {
        reader.readAsText(file);
      } else {
        reader.readAsDataURL(file);
      }
    });
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;

    const userMsg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsBrainThinking(true);

    const aiResponse = await queryKnowledgeBase(userMsg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: aiResponse }]);
    setIsBrainThinking(false);
  };

  const handleFolderClick = (id: string) => {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
    setSearchQuery('');
  };

  const handleBack = () => {
    if (path.length > 0) setPath(path.slice(0, -1));
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const navSections = useMemo(() => ({
    top: NAV_ITEMS.filter(i => i.section === 'top'),
    my_files: NAV_ITEMS.filter(i => i.section === 'my_files'),
    google_drive: NAV_ITEMS.filter(i => i.section === 'google_drive'),
    trash: NAV_ITEMS.filter(i => i.section === 'trash'),
  }), []);

  const selectedFile = useMemo(() => 
    selectedIds.length === 1 ? files.find(f => f.id === selectedIds[0]) : null
  , [selectedIds, files]);

  return (
    <div className="flex h-screen w-full bg-white select-none overflow-hidden relative">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Sidebar */}
      <aside className="w-64 border-r border-gray-200 flex flex-col bg-[#f8f9fa] z-10 shrink-0">
        <div className="p-4 mb-2">
          <div className="flex items-center gap-2 px-3 py-2 text-blue-600 font-medium text-lg tracking-tight">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-sm">
              <Plus size={20} />
            </div>
            <span className="font-semibold text-[#1a73e8]">{str('FILEMANAGER_APP_NAME')}</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-2 space-y-4">
          <div className="space-y-1">
            {navSections.top.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8] font-medium' : 'text-[#5f6368] hover:bg-[#e8eaed]'
                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="space-y-1">
            <div className="px-4 text-[11px] font-bold text-[#5f6368] uppercase tracking-wider mb-1">
              {str('MY_FILES_ROOT_LABEL')}
            </div>
            {navSections.my_files.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
