export enum FileType {
  FOLDER = 'folder',
  IMAGE = 'image',
  VIDEO = 'video',
  AUDIO = 'audio',
  DOCUMENT = 'document',
  ARCHIVE = 'archive',
  GENERIC = 'generic'
}

export interface FileItem {
  id: string;
  name: string;
  type: FileType;
  size: number | null;
  lastModified: string;
  parentId: string | null;
  extension?: string;
  mimeType?: string;
  // AI Knowledge Base fields
  content?: string; // Text content or Base64 string
  aiSummary?: string;
  aiKeywords?: string[];
  isIndexing?: boolean;
}

export interface NavigationState {
  currentPath: string[];
  selectedIds: string[];
  viewMode: 'list' | 'grid';
}

import { GoogleGenAI, Type } from "@google/genai";
import { FileItem, FileType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a semantic summary and keywords for a file to build the knowledge base.
 * Now supports multimodal input (images, PDFs, text).
 */
export async function indexFile(file: FileItem): Promise<{ summary: string; keywords: string[] }> {
  try {
    const parts: any[] = [];

    // If we have content and it's a type Gemini can "see" (Image or PDF)
    if (file.content && file.mimeType) {
      const isImage = file.mimeType.startsWith('image/');
      const isPdf = file.mimeType === 'application/pdf';

      if (isImage || isPdf) {
        // Extract base64 from DataURL if necessary
        const base64Data = file.content.includes('base64,') 
          ? file.content.split('base64,')[1] 
          : file.content;

        parts.push({
          inlineData: {
            data: base64Data,
            mimeType: file.mimeType
          }
        });
      }
    }

    const textPrompt = `Analyze this file to build a semantic knowledge base.
    File Name: ${file.name}
    File Type: ${file.type}
    ${file.extension ? `Extension: ${file.extension}` : ""}

    ${file.type === FileType.DOCUMENT && file.content && !file.mimeType?.includes('pdf')
      ? `Content Snippet: ${file.content.substring(0, 10000)}` 
      : "The file data is attached as a multimodal part."}

    Task:
    Return a JSON object with:
    1. "summary": A descriptive 1-2 sentence summary of the file's content/meaning.
    2. "keywords": 5 relevant tags for semantic search.`;

    parts.push({ text: textPrompt });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            keywords: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    return JSON.parse(response.text || '{"summary": "No summary available", "keywords": []}');
  } catch (error) {
    console.error("Indexing error:", error);
    return { summary: "Error indexing file content", keywords: [] };
  }
}

/**
 * Queries the entire knowledge base.
 */
export async function queryKnowledgeBase(query: string, files: FileItem[]): Promise<string> {
  const context = files
    .filter(f => f.aiSummary)
    .map(f => `[File: ${f.name}] Summary: ${f.aiSummary} Tags: ${f.aiKeywords?.join(", ")}`)
    .join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `You are the Knowledge Engine of a file system. 
    Use the following summaries of the user's files to answer their query.
    If multiple files are relevant, synthesize the information.
    If no files are relevant, explain that the knowledge base doesn't contain that info yet.

    File Knowledge Base:
    ${context || "No files indexed yet."}

    User Query: ${query}`,
  });

  return response.text || "I encountered an error processing the knowledge base.";
}

export async function smartSearch(query: string, files: FileItem[]): Promise<string[]> {
  try {
    const fileList = files.map(f => ({ 
      id: f.id, 
      name: f.name, 
      summary: f.aiSummary, 
      keywords: f.aiKeywords 
    }));

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User search query: "${query}". 
      Return an array of IDs for files that semantically match this query based on their names, summaries, or tags.
      Files available: ${JSON.stringify(fileList)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    return files
      .filter(f => f.name.toLowerCase().includes(query.toLowerCase()))
      .map(f => f.id);
  }
}

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  RotateCw, 
  LayoutGrid, 
  List, 
  MoreVertical, 
  ChevronRight, 
  ArrowLeft, 
  X, 
  Plus, 
  Folder, 
  Brain, 
  MessageSquare, 
  FileUp, 
  Sparkles, 
  Loader2,
  FolderPlus,
  Share2,
  Trash2,
  Download
} from 'lucide-react';
import { FileItem, FileType } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase } from './services/geminiService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  const filteredFiles = useMemo(() => {
    if (aiResults) return files.filter(f => aiResults.includes(f.id));
    if (searchQuery && !isSearching) {
      return files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return files.filter(f => f.parentId === currentFolderId);
  }, [files, currentFolderId, searchQuery, aiResults, isSearching]);

  const handleDelete = () => {
    const getDescendants = (parentId: string, allFiles: FileItem[]): string[] => {
      let descendants: string[] = [];
      const children = allFiles.filter(f => f.parentId === parentId);
      children.forEach(child => {
        descendants.push(child.id);
        if (child.type === FileType.FOLDER) {
          descendants = [...descendants, ...getDescendants(child.id, allFiles)];
        }
      });
      return descendants;
    };

    let allIdsToRemove = [...selectedIds];
    selectedIds.forEach(id => {
      const file = files.find(f => f.id === id);
      if (file?.type === FileType.FOLDER) {
        allIdsToRemove = [...allIdsToRemove, ...getDescendants(id, files)];
      }
    });

    const finalDeleteSet = new Set(allIdsToRemove);
    setFiles(prev => prev.filter(f => !finalDeleteSet.has(f.id)));
    setSelectedIds([]);
  };

  const handleShare = async () => {
    if (selectedIds.length === 0) return;
    const file = files.find(f => f.id === selectedIds[0]);
    if (!file) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: file.name,
          text: `AI-Indexed File: ${file.name}\n\nSummary: ${file.aiSummary || 'Not indexed yet.'}\n\nKeywords: ${file.aiKeywords?.join(', ') || 'None'}`,
          url: window.location.href,
        });
      } catch (err) {
        if ((err as Error).name !== 'AbortError') {
          console.error("Share failed:", err);
        }
      }
    } else {
      await navigator.clipboard.writeText(`${file.name}\n${file.aiSummary || ''}`);
      alert(`Summary of "${file.name}" copied to clipboard!`);
    }
  };

  const indexNewFile = async (newFile: FileItem) => {
    setFiles(prev => prev.map(f => f.id === newFile.id ? { ...f, isIndexing: true } : f));
    const result = await indexFile(newFile);
    setFiles(prev => prev.map(f => f.id === newFile.id ? { 
      ...f, 
      aiSummary: result.summary, 
      aiKeywords: result.keywords,
      isIndexing: false 
    } : f));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;

    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      const isText = file.type.startsWith('text/') || 
                     file.name.endsWith('.md') || 
                     file.name.endsWith('.js') || 
                     file.name.endsWith('.ts') || 
                     file.name.endsWith('.txt');
      const isMultimodal = file.type.startsWith('image/') || file.type === 'application/pdf';

      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : 
                file.type === 'application/pdf' ? FileType.DOCUMENT :
                file.type.startsWith('video/') ? FileType.VIDEO :
                file.type.startsWith('audio/') ? FileType.AUDIO : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          content: content,
          mimeType: file.type || (file.name.endsWith('.md') ? 'text/markdown' : 'text/plain'),
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        indexNewFile(newFile);
      };

      if (isText) {
        reader.readAsText(file);
      } else {
        // Images, PDFs, etc. need DataURL for base64 parts
        reader.readAsDataURL(file);
      }
    });
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;

    const userMsg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsBrainThinking(true);

    const aiResponse = await queryKnowledgeBase(userMsg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: aiResponse }]);
    setIsBrainThinking(false);
  };

  const handleFolderClick = (id: string) => {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
    setSearchQuery('');
  };

  const handleBack = () => {
    if (path.length > 0) setPath(path.slice(0, -1));
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const handleCreateFolder = () => {
    const name = prompt("Enter folder name:");
    if (!name) return;
    const newFolder: FileItem = {
      id: Math.random().toString(36).substring(2, 11),
      name: name,
      type: FileType.FOLDER,
      size: null,
      lastModified: new Date().toLocaleDateString(),
      parentId: currentFolderId
    };
    setFiles(prev => [...prev, newFolder]);
  };

  const navSections = useMemo(() => ({
    top: NAV_ITEMS.filter(i => i.section === 'top'),
    my_files: NAV_ITEMS.filter(i => i.section === 'my_files'),
    google_drive: NAV_ITEMS.filter(i => i.section === 'google_drive'),
    trash: NAV_ITEMS.filter(i => i.section === 'trash'),
  }), []);

  const selectedFile = useMemo(() => 
    selectedIds.length === 1 ? files.find(f => f.id === selectedIds[0]) : null
  , [selectedIds, files]);

  return (
    <div className="flex h-screen w-full bg-white select-none overflow-hidden relative text-[#3c4043]">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Sidebar */}
      <aside className="w-64 border-r border-gray-200 flex flex-col bg-[#f8f9fa] z-10 shrink-0">
        <div className="p-4 mb-2">
          <div className="flex items-center gap-2 px-3 py-2 text-blue-600 font-medium text-lg tracking-tight">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-sm">
              <Plus size={20} />
            </div>
            <span className="font-semibold text-[#1a73e8]">{str('FILEMANAGER_APP_NAME')}</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-2 space-y-4">
          <div className="space-y-1">
            {navSections.top.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8] font-medium' : 'text-[#5f6368] hover:bg-[#e8eaed]'
                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="space-y-1">
            <div className="px-4 text-[11px] font-bold text-[#5f6368] uppercase tracking-wider mb-1">
              {str('MY_FILES_ROOT_LABEL')}
            </div>
            {navSections.my_files.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8] font-medium' : 'text-[#5f6368] hover:bg-[#e8eaed]'
                }`}
              >
                {item.icon}
                {item.label}
              </button>
            ))}
          </div>

          <div className="px-4 py-3 bg-indigo-50 rounded-xl mx-2 border border-indigo-100 group cursor-pointer hover:bg-indigo-100 transition-colors"
               onClick={() => setIsBrainOpen(true)}>
            <div className="flex items-center gap-2 text-indigo-700 font-bold text-xs mb-1">
              <Brain size={14} className="animate-pulse" />
              SYSTEM BRAIN
            </div>
            <div className="text-[10px] text-indigo-600 font-medium">
              Ask about your {files.filter(f => f.aiSummary).length} indexed files.
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-gray-100">
          <div className="flex justify-between text-[11px] text-[#5f6368] mb-1.5 font-medium">
            <span>Knowledge Base Utility</span>
          </div>
          <div className="w-full h-1.5 bg-[#e8eaed] rounded-full overflow-hidden">
            <div 
              className="h-full bg-blue-500 rounded-full transition-all duration-1000" 
              style={{ width: `${files.length > 0 ? Math.min(100, (files.filter(f => f.aiSummary).length / files.length) * 100) : 0}%` }}
            ></div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        <header className="h-16 flex items-center justify-between px-6 border-b border-gray-100">
          <div className="flex items-center gap-3 min-w-0">
            {path.length > 0 && (
              <button onClick={handleBack} className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-1 overflow-hidden text-sm">
              <span className="text-[#5f6368] whitespace-nowrap">{NAV_ITEMS.find(n => n.id === currentNav)?.label}</span>
              {path.map((folderId, idx) => {
                const folder = files.find(f => f.id === folderId);
                return (
                  <React.Fragment key={folderId}>
                    <ChevronRight size={14} className="text-[#9aa0a6] flex-shrink-0" />
                    <span className={`whitespace-nowrap ${idx === path.length - 1 ? 'font-medium text-[#202124]' : 'text-[#5f6368] hover:underline cursor-pointer'}`}>
                      {folder?.name}
                    </span>
                  </React.Fragment>
                );
              })}
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="relative group">
              <div className="flex items-center bg-[#f1f3f4] rounded-xl focus-within:bg-white focus-within:shadow-md transition-all px-4 py-2 w-64 lg:w-96">
                <Search size={18} className="text-[#5f6368] mr-2" />
                <input 
                  type="text"
                  placeholder="Ask Gemini to find something..."
                  className="bg-transparent border-none outline-none text-sm w-full text-[#3c4043]"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
                />
                {searchQuery && (
                  <button onClick={() => {setSearchQuery(''); setAiResults(null);}} className="p-1 hover:bg-[#e8eaed] rounded-full">
                    <X size={14} className="text-[#5f6368]" />
                  </button>
                )}
              </div>
            </div>

            <button onClick={() => setIsBrainOpen(!isBrainOpen)} className={`p-2 rounded-full transition-colors ${isBrainOpen ? 'bg-indigo-100 text-indigo-700' : 'hover:bg-[#e8eaed] text-[#5f6368]'}`}>
              <Brain size={20} />
            </button>
            <button className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]">
              <RotateCw size={20} />
            </button>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : 'list')}
              className="p-2 hover:bg-[#e8eaed] rounded-full transition-colors text-[#5f6368]"
            >
              {viewMode === 'list' ? <LayoutGrid size={20} /> : <List size={20} />}
            </button>
          </div>
        </header>

        {/* Gemini Insight Overlay */}
        {selectedFile && (
          <div className="px-6 py-4 border-b border-indigo-50 bg-indigo-50/20 animate-in slide-in-from-top duration-300">
            <div className="flex items-start gap-4">
              <div className="p-2 bg-white rounded-lg shadow-sm border border-indigo-100">
                <Sparkles size={16} className="text-indigo-600" />
              </div>
              <div className="flex-1">
                <div className="text-xs font-bold text-indigo-700 mb-1 flex items-center gap-2 uppercase tracking-wide">
                  Gemini Knowledge Index
                  {selectedFile.isIndexing && <Loader2 size={12} className="animate-spin" />}
                </div>
                <p className="text-sm text-[#3c4043] leading-relaxed">
                  {selectedFile.isIndexing ? "Gemini is currently reading and understanding this file..." : (selectedFile.aiSummary || "This file has not been indexed yet.")}
                </p>
                {selectedFile.aiKeywords && !selectedFile.isIndexing && (
                  <div className="flex flex-wrap gap-2 mt-2">
                    {selectedFile.aiKeywords.map(k => (
                      <span key={k} className="text-[10px] bg-white border border-indigo-100 text-indigo-600 px-2 py-0.5 rounded-full font-bold">#{k}</span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Action Bar */}
        {selectedIds.length > 0 && (
          <div className="h-12 bg-[#e8f0fe] border-b border-[#d2e3fc] flex items-center px-6 justify-between animate-in slide-in-from-top duration-200">
            <div className="flex items-center gap-4">
              <button onClick={() => setSelectedIds([])} className="text-[#1a73e8] hover:bg-[#d2e3fc] p-1 rounded-full transition-colors">
                <X size={18} />
              </button>
              <span className="text-[#185abc] text-sm font-medium">{selectedIds.length} item(s) selected</span>
            </div>
            <div className="flex items-center gap-6">
              <button onClick={handleShare} className="flex items-center gap-1.5 text-sm font-semibold text-[#1a73e8] hover:underline">
                <Share2 size={16} /> Share
              </button>
              <button className="flex items-center gap-1.5 text-sm font-semibold text-[#1a73e8] hover:underline">
                <Download size={16} /> Download
              </button>
              <button onClick={handleDelete} className="flex items-center gap-1.5 text-sm font-semibold text-[#d93025] hover:underline">
                <Trash2 size={16} /> {str('DELETE_BUTTON_LABEL')}
              </button>
            </div>
          </div>
        )}

        {/* Search Results Banner */}
        {aiResults && (
           <div className="px-6 py-2.5 bg-gradient-to-r from-[#e8f0fe] to-[#f3e8ff] border-b border-blue-100 flex items-center justify-between">
             <div className="flex items-center gap-2 text-sm text-[#185abc] font-medium italic">
               <Sparkles size={14} />
               <span>AI Semantic Filter: "{searchQuery}"</span>
             </div>
             <button onClick={() => {setAiResults(null); setSearchQuery('');}} className="text-[10px] bg-white text-blue-600 px-3 py-1 rounded-full font-bold hover:bg-white shadow-sm border border-blue-100">CLEAR</button>
           </div>
        )}

        {/* File Browser */}
        <div className="flex-1 overflow-auto bg-white relative">
          {isSearching ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-500 gap-4">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-indigo-50 border-t-indigo-600 rounded-full animate-spin"></div>
                <Brain className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-600" size={24} />
              </div>
              <p className="text-sm font-semibold text-indigo-700">Gemini is scanning your knowledge base...</p>
            </div>
          ) : filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-[#9aa0a6] text-center p-8">
              <div className="w-32 h-32 mb-6 bg-[#f8f9fa] rounded-full flex items-center justify-center shadow-inner text-[#e8eaed]">
                <Folder size={64} />
              </div>
              <h3 className="text-xl font-bold text-[#5f6368] mb-2">No files here yet</h3>
              <p className="text-sm max-w-xs">Upload your documents or images to start building your AI knowledge base.</p>
            </div>
          ) : viewMode === 'list' ? (
            <table className="w-full border-collapse text-[13px]">
              <thead>
                <tr className="text-left text-[#5f6368] border-b border-gray-100 sticky top-0 bg-white z-10">
                  <th className="font-semibold p-3 pl-6 w-[45%]">{str('NAME_COLUMN_LABEL')}</th>
                  <th className="font-semibold p-3 w-[15%]">{str('SIZE_COLUMN_LABEL')}</th>
                  <th className="font-semibold p-3 w-[20%]">Gemini Status</th>
                  <th className="font-semibold p-3 pr-6 w-[20%]">{str('DATE_COLUMN_LABEL')}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {filteredFiles.map((file) => (
                  <tr 
                    key={file.id}
                    onClick={(e) => toggleSelect(file.id, e)}
                    onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                    className={`hover:bg-[#f8f9fa] cursor-default transition-colors group ${
                      selectedIds.includes(file.id) ? 'bg-[#e8f0fe] text-[#185abc]' : 'text-[#3c4043]'
                    }`}
                  >
                    <td className="p-3 pl-6">
                      <div className="flex items-center gap-3">
                        <div className="transition-transform group-hover:scale-110 duration-200">
                          {getFileIcon(file.type)}
                        </div>
                        <span className="truncate max-w-xs font-medium">{file.name}</span>
                      </div>
                    </td>
                    <td className="p-3 text-[#5f6368]">
                      {formatSize(file.size)}
                    </td>
                    <td className="p-3">
                      {file.isIndexing ? (
                        <span className="flex items-center gap-2 text-indigo-500 font-bold animate-pulse">
                          <Loader2 size={12} className="animate-spin" /> Reading...
                        </span>
                      ) : file.aiSummary ? (
                        <span className="text-emerald-600 flex items-center gap-1.5 font-bold">
                          <Sparkles size={12} /> Indexed
                        </span>
                      ) : <span className="text-gray-400 font-medium">Not Indexed</span>}
                    </td>
                    <td className="p-3 pr-6 text-[#5f6368]">
                      {file.lastModified}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6 p-6">
              {filteredFiles.map((file) => (
                <div 
                  key={file.id}
                  onClick={(e) => toggleSelect(file.id, e)}
                  onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                  className={`flex flex-col items-center p-4 rounded-2xl border transition-all relative group/item ${
                    selectedIds.includes(file.id) 
                    ? 'bg-[#e8f0fe] border-[#1a73e8] ring-1 ring-[#1a73e8] shadow-md scale-105' 
                    : 'bg-white border-transparent hover:bg-[#f1f3f4] hover:border-gray-200'
                  }`}
                >
                  {file.aiSummary && !file.isIndexing && (
                    <div className="absolute top-2 right-2 text-emerald-500">
                      <Sparkles size={14} />
                    </div>
                  )}
                  {file.isIndexing && (
                    <div className="absolute top-2 right-2 text-indigo-500 animate-spin">
                      <Loader2 size={14} />
                    </div>
                  )}
                  <div className="mb-4 transition-transform group-hover/item:scale-110">
                    {React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: 56 })}
                  </div>
                  <span className="text-center text-xs font-bold truncate w-full px-2">
                    {file.name}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer Actions */}
        <footer className="bg-white border-t border-gray-200 h-20 flex items-center justify-between px-6 z-20 shrink-0">
           <div className="flex gap-3">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 px-6 py-3 bg-[#1a73e8] text-white rounded-full hover:bg-blue-700 transition-all shadow-md active:scale-95 font-bold text-sm"
              >
                 <FileUp size={20} />
                 <span>Upload & Index</span>
              </button>
              <button 
                onClick={handleCreateFolder}
                className="flex items-center gap-2 px-6 py-3 bg-white text-[#3c4043] border border-gray-200 rounded-full hover:bg-gray-50 transition-all active:scale-95 font-bold text-sm"
              >
                 <FolderPlus size={20} />
                 <span>New Folder</span>
              </button>
           </div>
           <div className="flex gap-4">
              <button className="text-sm font-bold text-[#5f6368] hover:bg-[#f1f3f4] px-6 py-3 rounded-full transition-colors">Cancel</button>
              <button 
                disabled={selectedIds.length === 0}
                className={`px-10 py-3 rounded-full text-sm font-bold transition-all ${selectedIds.length > 0 ? 'bg-[#1a73e8] text-white shadow-lg active:scale-95' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
              >
                Open
              </button>
           </div>
        </footer>
      </main>

      {/* System Brain Slide-out */}
      <div className={`fixed right-0 top-0 h-full w-[450px] bg-white border-l border-gray-200 shadow-2xl transition-transform duration-500 z-50 flex flex-col ${isBrainOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 border-b border-gray-200 bg-[#f8f9fa] flex items-center justify-between">
          <div className="flex items-center gap-3 text-indigo-700">
            <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center shadow-sm">
              <Brain size={28} />
            </div>
            <div>
              <div className="text-lg font-black tracking-tight">KNOWLEDGE ENGINE</div>
              <div className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest flex items-center gap-1">
                <Sparkles size={10} /> Powered by Gemini
              </div>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-2 hover:bg-gray-200 rounded-full text-gray-400 transition-colors">
