                </div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-6 bg-white border-t border-gray-200">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Ask your knowledge base..."
              className="w-full bg-[#f1f3f4] border-none outline-none py-4 pl-5 pr-14 rounded-2xl text-sm font-medium focus:ring-2 focus:ring-indigo-100 transition-all"
              value={brainInput}
              onChange={(e) => setBrainInput(e.target.value)}
            />
            <button className="absolute right-3 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all shadow-md active:scale-95">
              <Sparkles size={18} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export enum FileType {
  FOLDER = 'folder',
  IMAGE = 'image',
  VIDEO = 'video',
  AUDIO = 'audio',
  DOCUMENT = 'document',
  ARCHIVE = 'archive',
  GENERIC = 'generic'
}

export type FileSource = 'local' | 'github' | 'ai';

export interface FileItem {
  id: string;
  name: string;
  type: FileType;
  size: number | null;
  lastModified: string;
  parentId: string | null;
  source: FileSource;
  extension?: string;
  mimeType?: string;
  content?: string; // Text or DataURL
  // AI fields
  aiSummary?: string;
  aiKeywords?: string[];
  isIndexing?: boolean;
  // Source metadata
  githubRepo?: string;
  githubOwner?: string;
  githubUrl?: string;
}

export interface NavigationState {
  currentPath: string[];
  selectedIds: string[];
  viewMode: 'list' | 'grid' | 'gallery';
}

import { FileItem, FileType } from "../types";

const GITHUB_API = "https://api.github.com";

export async function fetchUserRepos(username: string): Promise<any[]> {
  try {
    const response = await fetch(`${GITHUB_API}/users/${username}/repos?sort=updated&per_page=10`);
    if (!response.ok) throw new Error("User not found");
    return await response.json();
  } catch (error) {
    console.error("GitHub fetch error:", error);
    return [];
  }
}

export async function fetchRepoContents(owner: string, repo: string, path: string = ""): Promise<any[]> {
  try {
    const response = await fetch(`${GITHUB_API}/repos/${owner}/${repo}/contents/${path}`);
    if (!response.ok) return [];
    return await response.json();
  } catch (error) {
    return [];
  }
}

export function mapGithubToFiles(
  ghItems: any[], 
  parentId: string, 
  owner: string, 
  repoName: string,
  source: 'github' = 'github'
): FileItem[] {
  return ghItems.map(item => ({
    id: `gh-${item.sha || Math.random().toString(36).substr(2, 9)}`,
    name: item.name,
    type: item.type === 'dir' ? FileType.FOLDER : FileType.DOCUMENT,
    size: item.size || null,
    lastModified: new Date().toLocaleDateString(),
    parentId,
    source,
    githubOwner: owner,
    githubRepo: repoName,
    githubUrl: item.html_url,
    extension: item.name.split('.').pop(),
    mimeType: item.type === 'dir' ? undefined : 'text/plain' // Fallback
  }));
}

import { GoogleGenAI, Type } from "@google/genai";
import { FileItem, FileType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates an image based on text prompt.
 */
export async function generateAIImage(prompt: string): Promise<{ dataUrl: string; caption: string }> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let dataUrl = "";
    let caption = "";

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        dataUrl = `data:image/png;base64,${part.inlineData.data}`;
      } else if (part.text) {
        caption = part.text;
      }
    }

    if (!dataUrl) throw new Error("No image data received");
    return { dataUrl, caption };
  } catch (error) {
    console.error("Image generation error:", error);
    throw error;
  }
}

export async function indexFile(file: FileItem): Promise<{ summary: string; keywords: string[] }> {
  try {
    const parts: any[] = [];
    if (file.content && file.mimeType) {
      const isImage = file.mimeType.startsWith('image/');
      const isPdf = file.mimeType === 'application/pdf';
      if (isImage || isPdf) {
        const base64Data = file.content.includes('base64,') ? file.content.split('base64,')[1] : file.content;
        parts.push({ inlineData: { data: base64Data, mimeType: file.mimeType } });
      }
    }

    const textPrompt = `Analyze this ${file.source} file. 
    Name: ${file.name}
    Type: ${file.type}
    Return JSON: {"summary": "1-2 sentence description", "keywords": ["tag1", "tag2", "tag3", "tag4", "tag5"]}`;

    parts.push({ text: textPrompt });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            keywords: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });
    return JSON.parse(response.text || '{"summary": "No summary available", "keywords": []}');
  } catch (error) {
    return { summary: "Error indexing file", keywords: [] };
  }
}

export async function queryKnowledgeBase(query: string, files: FileItem[]): Promise<string> {
  const context = files
    .filter(f => f.aiSummary)
    .map(f => `[File: ${f.name} (Source: ${f.source})] Summary: ${f.aiSummary}`)
    .join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `You are the Brain of a integrated workspace. 
    Context:
    ${context || "No files available."}

    Question: ${query}`,
  });
  return response.text || "No response.";
}

export async function smartSearch(query: string, files: FileItem[]): Promise<string[]> {
  try {
    const fileList = files.map(f => ({ id: f.id, name: f.name, summary: f.aiSummary }));
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search: "${query}". Return IDs for relevant matches: ${JSON.stringify(fileList)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return files.filter(f => f.name.toLowerCase().includes(query.toLowerCase())).map(f => f.id);
  }
}

