      </main>

      {/* AI Image Studio Modal */}
      {isStudioOpen && (
        <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6 animate-in fade-in">
           <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 bg-indigo-600 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <Palette size={32}/>
                  <div>
                    <h2 className="text-2xl font-black">AI Image Studio</h2>
                    <p className="text-xs text-indigo-100">Powered by Gemini 2.5 Flash</p>
                  </div>
                </div>
                <button onClick={() => setIsStudioOpen(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X/></button>
              </div>
              <div className="p-10">
                <form onSubmit={handleGenerateImage} className="space-y-6">
                   <div>
                     <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest block mb-2">Image Prompt</label>
                     <textarea 
                       value={studioPrompt}
                       onChange={(e) => setStudioPrompt(e.target.value)}
                       placeholder="Describe the image you want to generate..."
                       className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-none outline-none text-gray-800 placeholder:text-gray-300 font-medium text-lg resize-none shadow-inner focus:ring-4 focus:ring-indigo-50 transition-all"
                     />
                   </div>
                   <button 
                    disabled={isGenerating || !studioPrompt.trim()}
                    className="w-full py-5 bg-indigo-600 text-white rounded-3xl font-black text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-4 disabled:opacity-50"
                   >
                     {isGenerating ? (
                       <><Loader2 className="animate-spin" /> Creating your art...</>
                     ) : (
                       <><Sparkles /> Generate & Save to Gallery</>
                     )}
                   </button>
                </form>
              </div>
           </div>
        </div>
      )}

      {/* Brain Slide-out */}
      <div className={`fixed right-0 top-0 h-full w-[450px] bg-white border-l border-gray-100 shadow-2xl transition-transform duration-500 z-50 flex flex-col ${isBrainOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-8 border-b border-gray-100 flex items-center justify-between">
          <div className="flex items-center gap-4 text-indigo-600">
            <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center shadow-inner">
              <Brain size={32}/>
            </div>
            <div>
              <h2 className="text-xl font-black tracking-tight">KNOWLEDGE ENGINE</h2>
              <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Scanning local + GitHub</p>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-2 hover:bg-gray-100 rounded-full text-gray-400"><X size={24}/></button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-6">
          {brainChat.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
              <div className={`max-w-[90%] px-6 py-4 rounded-[30px] text-sm leading-relaxed shadow-sm border ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none border-transparent' : 'bg-gray-50 text-gray-800 rounded-tl-none border-gray-100'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isBrainThinking && (
            <div className="flex justify-start">
              <div className="bg-gray-50 px-6 py-4 rounded-[30px] rounded-tl-none border border-gray-100 flex gap-2">
                <div className="w-2 h-2 bg-indigo-200 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-8 bg-white border-t border-gray-100">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Ask about your repositories..."
              className="w-full bg-gray-100 border-none outline-none py-5 pl-6 pr-16 rounded-[25px] text-sm font-bold placeholder:text-gray-400 focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all"
              value={brainInput}
              onChange={(e) => setBrainInput(e.target.value)}
            />
            <button className="absolute right-3 top-1/2 -translate-y-1/2 p-3 bg-indigo-600 text-white rounded-2xl shadow-lg hover:bg-indigo-700 transition-all">
              <MessageSquare size={18}/>
            </button>
          </div>
        </form>
      </div>
    </div>
  );

  function handleFolderClick(id: string) {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
  }

  function toggleSelect(id: string, e: React.MouseEvent) {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  }
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Search, RotateCw, LayoutGrid, List, MoreVertical, ChevronRight, 
  ArrowLeft, X, Plus, Folder, Brain, MessageSquare, FileUp, Sparkles, 
  Loader2, FolderPlus, Share2, Trash2, Download, Github, Palette,
  Globe, UserPlus, Image as ImageIcon, HardDrive
} from 'lucide-react';
import { FileItem, FileType, FileSource } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase, generateAIImage } from './services/geminiService';
import { fetchUserRepos, mapGithubToFiles } from './services/githubService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'gallery'>('list');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);

  // Brain State
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);

  // AI Image State
  const [isStudioOpen, setIsStudioOpen] = useState(false);
  const [studioPrompt, setStudioPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // GitHub State
  const [githubUsers, setGithubUsers] = useState<string[]>(['jocall3']);
  const [isSyncing, setIsSyncing] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  // Initialize: Load default user
  useEffect(() => {
    githubUsers.forEach(user => syncUser(user));
  }, []);

  const filteredFiles = useMemo(() => {
    if (aiResults) return files.filter(f => aiResults.includes(f.id));
    if (searchQuery && !isSearching) {
      return files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return files.filter(f => f.parentId === currentFolderId);
  }, [files, currentFolderId, searchQuery, aiResults, isSearching]);

  const syncUser = async (username: string) => {
    setIsSyncing(true);
    const repos = await fetchUserRepos(username);
    const mapped = mapGithubToFiles(repos, 'root', username, "Repositories");
    setFiles(prev => {
      // Avoid duplicates
      const others = prev.filter(f => !(f.source === 'github' && f.githubOwner === username));
      return [...others, ...mapped];
    });
    setIsSyncing(false);
  };

  const handleAddGithubUser = () => {
    const username = prompt("Enter GitHub username:");
    if (username && !githubUsers.includes(username)) {
      setGithubUsers(prev => [...prev, username]);
      syncUser(username);
    }
  };

  // Fixed: handleSmartSearch implementation for AI-driven searching
  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    try {
      const results = await smartSearch(searchQuery, files);
      setAiResults(results);
    } catch (err) {
      console.error("Smart search failed:", err);
      setAiResults(null);
    } finally {
      setIsSearching(false);
    }
  };

  const handleGenerateImage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studioPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const result = await generateAIImage(studioPrompt);
      const newFile: FileItem = {
        id: `ai-${Date.now()}`,
        name: `AI Gen - ${studioPrompt.substring(0, 15)}...`,
        type: FileType.IMAGE,
        size: result.dataUrl.length,
        lastModified: new Date().toLocaleDateString(),
        parentId: 'root',
        source: 'ai',
        content: result.dataUrl,
        mimeType: 'image/png',
        aiSummary: studioPrompt,
        aiKeywords: ['generated', 'ai-art', 'gemini']
      };
      setFiles(prev => [...prev, newFile]);
      setStudioPrompt('');
      setIsStudioOpen(false);
      setCurrentNav('root'); // Go to where it was saved
    } catch (err) {
      alert("Failed to generate image. Try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDelete = () => {
    setFiles(prev => prev.filter(f => !selectedIds.includes(f.id)));
    setSelectedIds([]);
  };

  const handleShare = async () => {
    if (selectedIds.length === 0) return;
    const file = files.find(f => f.id === selectedIds[0]);
    if (!file) return;
    if (navigator.share) {
      navigator.share({ title: file.name, text: file.aiSummary, url: file.githubUrl || window.location.href });
    } else {
      alert("Link copied to clipboard!");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;
    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          source: 'local',
          content,
          mimeType: file.type,
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        const indexRes = await indexFile(newFile);
        setFiles(p => p.map(f => f.id === newFile.id ? { ...f, aiSummary: indexRes.summary, aiKeywords: indexRes.keywords } : f));
      };
      file.type.startsWith('text/') ? reader.readAsText(file) : reader.readAsDataURL(file);
    });
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;
    const msg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: msg }]);
    setIsBrainThinking(true);
    const res = await queryKnowledgeBase(msg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: res }]);
    setIsBrainThinking(false);
  };

  const navSections = useMemo(() => ({
    top: NAV_ITEMS.filter(i => i.section === 'top'),
    my_files: NAV_ITEMS.filter(i => i.section === 'my_files'),
    github: githubUsers.map(u => ({ id: `gh-${u}`, label: u, icon: <Github size={18}/> })),
  }), [githubUsers]);

  const selectedFile = useMemo(() => files.find(f => f.id === selectedIds[0]), [selectedIds, files]);

  return (
    <div className="flex h-screen w-full bg-[#f8f9fa] select-none overflow-hidden relative font-sans text-[#3c4043]">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Sidebar */}
      <aside className="w-68 border-r border-gray-200 flex flex-col bg-white z-10 shrink-0 shadow-sm">
        <div className="p-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
              {/* Fixed: HardDrive icon is now imported */}
              <HardDrive size={24} />
            </div>
            <div className="font-bold text-xl tracking-tight text-gray-800">Workspace</div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-3 space-y-6">
          <div className="space-y-1">
            {navSections.top.map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${
                  currentNav === item.id ? 'bg-blue-50 text-[#1a73e8]' : 'hover:bg-gray-100 text-gray-600'
                }`}
              >
                {item.icon} {item.label}
              </button>
            ))}
          </div>

          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 flex justify-between items-center">
              <span>GitHub Hub</span>
              <button onClick={handleAddGithubUser} className="hover:text-blue-600 transition-colors"><UserPlus size={14}/></button>
            </div>
            {navSections.github.map(item => (
              <button
                key={item.id}
                className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium hover:bg-gray-100 text-gray-600"
              >
                {item.icon} {item.label}
                {isSyncing && <Loader2 size={12} className="animate-spin ml-auto"/>}
              </button>
            ))}
          </div>

          <div className="space-y-2 pt-4">
             <button 
              onClick={() => setIsStudioOpen(true)}
              className="w-full flex items-center gap-3 px-4 py-4 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-600 text-white shadow-md hover:shadow-lg transition-all active:scale-95 group"
             >
                <Palette size={20} className="group-hover:rotate-12 transition-transform" />
                <div className="text-left">
                  <div className="text-xs font-bold leading-none">AI Image Studio</div>
                  <div className="text-[9px] opacity-70 mt-1">Generate pictures with Gemini</div>
                </div>
             </button>

             <button 
               onClick={() => setIsBrainOpen(true)}
               className="w-full flex items-center gap-3 px-4 py-4 rounded-2xl bg-white border border-indigo-100 text-indigo-700 hover:bg-indigo-50 transition-all"
             >
                <Brain size={20} className="animate-pulse" />
                <div className="text-left">
                  <div className="text-xs font-bold leading-none">Workspace Brain</div>
                  <div className="text-[9px] text-indigo-500 mt-1">Ask questions about files</div>
                </div>
             </button>
          </div>
        </div>

        <div className="p-6 border-t border-gray-100">
           <div className="text-[10px] font-bold text-gray-400 uppercase mb-2">Power Status</div>
           <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
             <div className="h-full bg-blue-500 w-3/4 rounded-full"></div>
           </div>
        </div>
      </aside>

      {/* Main Main */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        <header className="h-20 flex items-center justify-between px-8 border-b border-gray-100 bg-white/80 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-4 min-w-0">
            {path.length > 0 && (
              <button onClick={() => setPath(path.slice(0, -1))} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-2 overflow-hidden text-sm">
              <span className="font-bold text-gray-800 text-lg">{NAV_ITEMS.find(n => n.id === currentNav)?.label || currentNav}</span>
              {path.map((folderId) => (
                <React.Fragment key={folderId}>
                  <ChevronRight size={16} className="text-gray-300" />
                  <span className="font-medium text-gray-500">{files.find(f => f.id === folderId)?.name}</span>
                </React.Fragment>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex items-center bg-gray-100 rounded-2xl px-5 py-2.5 w-80 lg:w-[450px] focus-within:bg-white focus-within:ring-2 focus-within:ring-blue-100 transition-all shadow-inner border border-transparent focus-within:border-blue-200">
              <Search size={18} className="text-gray-400 mr-3" />
              <input 
                type="text"
                placeholder="Search local, GitHub, or AI files..."
                className="bg-transparent border-none outline-none text-sm w-full font-medium"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
              />
            </div>
            <button className="p-2.5 hover:bg-gray-100 rounded-xl transition-colors text-gray-500">
              <RotateCw size={20} />
            </button>
          </div>
        </header>

        {/* Action Overlay */}
        {selectedFile && (
          <div className="mx-8 mt-4 p-5 rounded-3xl bg-indigo-50/50 border border-indigo-100 flex items-start gap-5 animate-in slide-in-from-top-4">
            <div className="p-3 bg-white rounded-2xl shadow-sm">
              {getFileIcon(selectedFile.type)}
            </div>
            <div className="flex-1 min-w-0">
               <div className="flex items-center gap-2 text-[10px] font-black uppercase text-indigo-600 tracking-widest mb-1">
                 <span>{selectedFile.source} Intelligence</span>
                 {selectedFile.source === 'github' && <Github size={12}/>}
               </div>
               <h3 className="font-bold text-gray-800 truncate">{selectedFile.name}</h3>
               <p className="text-xs text-gray-500 mt-1 leading-relaxed">
                 {selectedFile.aiSummary || "Indexing file contents for AI insights..."}
               </p>
            </div>
            <div className="flex flex-col gap-2">
               <button onClick={handleShare} className="px-4 py-1.5 bg-indigo-600 text-white rounded-xl text-xs font-bold shadow-sm hover:bg-indigo-700 transition-colors flex items-center gap-2">
                 <Share2 size={14}/> Share
               </button>
               <button onClick={handleDelete} className="px-4 py-1.5 bg-white text-red-500 border border-red-100 rounded-xl text-xs font-bold hover:bg-red-50 transition-colors flex items-center gap-2">
                 <Trash2 size={14}/> Delete
               </button>
            </div>
          </div>
        )}

        {/* Content Viewer */}
        <div className="flex-1 overflow-auto p-8">
          {filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
              <div className="w-32 h-32 bg-gray-50 rounded-full flex items-center justify-center mb-6">
                <Globe size={64}/>
              </div>
              <h2 className="text-xl font-black text-gray-800">Your space is empty</h2>
              <p className="text-sm max-w-xs mt-2">Connect a GitHub account or upload local files to get started.</p>
            </div>
          ) : (
            <div className={`grid gap-6 ${viewMode === 'list' ? 'grid-cols-1' : 'grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6'}`}>
              {filteredFiles.map(file => (
                <div 
                  key={file.id}
                  onClick={(e) => toggleSelect(file.id, e)}
                  onDoubleClick={() => file.type === FileType.FOLDER && handleFolderClick(file.id)}
                  className={`group relative flex flex-col p-4 rounded-3xl border transition-all cursor-pointer ${
                    selectedIds.includes(file.id) 
                    ? 'bg-blue-50 border-blue-200 ring-4 ring-blue-50/50 scale-105' 
                    : 'bg-white border-gray-100 hover:border-gray-200 hover:shadow-md'
                  }`}
                >
                  <div className="absolute top-3 right-3 flex gap-1">
                    {file.source === 'github' && <Github size={12} className="text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity"/>}
                    {file.source === 'ai' && <Sparkles size={12} className="text-purple-500"/>}
                  </div>

                  <div className={`aspect-square mb-4 rounded-2xl flex items-center justify-center transition-transform group-hover:scale-110 ${file.type === FileType.IMAGE && file.content ? 'bg-gray-50 overflow-hidden' : ''}`}>
                    {file.type === FileType.IMAGE && file.content ? (
                      <img src={file.content} className="w-full h-full object-cover" />
                    ) : (
                      getFileIcon(file.type)
                    )}
                  </div>

                  <span className="text-xs font-bold text-gray-800 truncate text-center">{file.name}</span>
                  <span className="text-[10px] text-gray-400 mt-1 text-center">{formatSize(file.size)}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="h-24 px-8 border-t border-gray-100 bg-white flex items-center justify-between">
           <div className="flex gap-4">
             <button 
               onClick={() => fileInputRef.current?.click()}
               className="flex items-center gap-3 px-6 py-3 bg-gray-900 text-white rounded-2xl font-bold text-sm shadow-xl active:scale-95 transition-all"
             >
               <FileUp size={20}/> Upload Work
             </button>
             <button 
               onClick={() => setIsStudioOpen(true)}
               className="flex items-center gap-3 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-xl active:scale-95 transition-all"
             >
               <Palette size={20}/> AI Gen Studio
             </button>
           </div>

           <div className="flex items-center gap-3">
             <button 
              onClick={() => setViewMode(viewMode === 'grid' ? 'list' : 'grid')}
              className="p-3 bg-gray-50 text-gray-500 rounded-2xl hover:bg-gray-100 transition-all"
             >
               {viewMode === 'grid' ? <List size={20}/> : <LayoutGrid size={20}/>}
             </button>
             <button className="px-10 py-3 bg-blue-600 text-white rounded-2xl font-black text-sm shadow-lg disabled:opacity-30 disabled:grayscale" disabled={selectedIds.length === 0}>
               OPEN
             </button>
           </div>
        </footer>
      </main>

      {/* AI Image Studio Modal */}
      {isStudioOpen && (
        <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6 animate-in fade-in">
           <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-xl overflow-hidden animate-in zoom-in-95">
              <div className="p-8 bg-indigo-600 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <Palette size={32}/>
                  <div>
                    <h2 className="text-2xl font-black">AI Image Studio</h2>
                    <p className="text-xs text-indigo-100">Powered by Gemini 2.5 Flash</p>
                  </div>
                </div>
                <button onClick={() => setIsStudioOpen(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X/></button>
              </div>
              <div className="p-10">
                <form onSubmit={handleGenerateImage} className="space-y-6">
                   <div>
                     <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest block mb-2">Image Prompt</label>
                     <textarea 
                       value={studioPrompt}
                       onChange={(e) => setStudioPrompt(e.target.value)}
                       placeholder="Describe the image you want to generate..."
                       className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-none outline-none text-gray-800 placeholder:text-gray-300 font-medium text-lg resize-none shadow-inner focus:ring-4 focus:ring-indigo-50 transition-all"
                     />
                   </div>
                   <button 
