        <div className="p-8 border-b border-gray-100 flex items-center justify-between">
          <div className="flex items-center gap-4 text-indigo-600">
            <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center shadow-inner">
              <Brain size={32}/>
            </div>
            <div>
              <h2 className="text-xl font-black tracking-tight">KNOWLEDGE ENGINE</h2>
              <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Scanning local + GitHub</p>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-2 hover:bg-gray-100 rounded-full text-gray-400"><X size={24}/></button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-6">
          {brainChat.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
              <div className={`max-w-[90%] px-6 py-4 rounded-[30px] text-sm leading-relaxed shadow-sm border ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none border-transparent' : 'bg-gray-50 text-gray-800 rounded-tl-none border-gray-100'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isBrainThinking && (
            <div className="flex justify-start">
              <div className="bg-gray-50 px-6 py-4 rounded-[30px] rounded-tl-none border border-gray-100 flex gap-2">
                <div className="w-2 h-2 bg-indigo-200 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-8 bg-white border-t border-gray-100">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Ask about your repositories..."
              className="w-full bg-gray-100 border-none outline-none py-5 pl-6 pr-16 rounded-[25px] text-sm font-bold placeholder:text-gray-400 focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all"
              value={brainInput}
              onChange={(e) => setBrainInput(e.target.value)}
            />
            <button className="absolute right-3 top-1/2 -translate-y-1/2 p-3 bg-indigo-600 text-white rounded-2xl shadow-lg hover:bg-indigo-700 transition-all">
              <MessageSquare size={18}/>
            </button>
          </div>
        </form>
      </div>
    </div>
  );

  function handleFolderClick(id: string) {
    setPath([...path, id]);
    setSelectedIds([]);
    setAiResults(null);
  }

  function toggleSelect(id: string, e: React.MouseEvent) {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedIds([id]);
    }
  }
}

import { FileItem, FileType } from "../types";

const GITHUB_API = "https://api.github.com";

export async function fetchUserRepos(username: string): Promise<any[]> {
  try {
    const response = await fetch(`${GITHUB_API}/users/${username}/repos?sort=updated&per_page=30`);
    if (!response.ok) throw new Error("User not found");
    return await response.json();
  } catch (error) {
    console.error("GitHub fetch error:", error);
    return [];
  }
}

export async function fetchRepoContents(owner: string, repo: string, path: string = ""): Promise<any[]> {
  try {
    const response = await fetch(`${GITHUB_API}/repos/${owner}/${repo}/contents/${path}`);
    if (!response.ok) return [];
    return await response.json();
  } catch (error) {
    console.error("GitHub contents fetch error:", error);
    return [];
  }
}

export async function fetchRawGithubContent(downloadUrl: string): Promise<string> {
  try {
    const response = await fetch(downloadUrl);
    if (!response.ok) return "Error fetching content.";
    return await response.text();
  } catch (error) {
    return "Failed to load file content.";
  }
}

export function mapGithubToFiles(
  ghItems: any[], 
  parentId: string, 
  owner: string, 
  repoName: string
): FileItem[] {
  return ghItems.map(item => {
    const isRepo = !!item.full_name; // Repos have full_name, contents don't
    const type = (isRepo || item.type === 'dir') ? FileType.FOLDER : FileType.DOCUMENT;

    return {
      id: isRepo ? `repo-${item.id}` : `gh-${item.sha || Math.random().toString(36).substr(2, 9)}`,
      name: item.name,
      type: type,
      size: item.size || null,
      lastModified: item.updated_at ? new Date(item.updated_at).toLocaleDateString() : new Date().toLocaleDateString(),
      parentId,
      source: 'github',
      githubOwner: owner,
      githubRepo: isRepo ? item.name : repoName,
      githubUrl: item.html_url,
      content: item.download_url, // Use this to fetch actual text later
      extension: item.name.split('.').pop(),
      mimeType: (isRepo || item.type === 'dir') ? undefined : 'text/plain'
    };
  });
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Search, RotateCw, LayoutGrid, List, MoreVertical, ChevronRight, 
  ArrowLeft, X, Plus, Folder, Brain, MessageSquare, FileUp, Sparkles, 
  Loader2, FolderPlus, Share2, Trash2, Download, Github, Palette,
  Globe, UserPlus, Image as ImageIcon, HardDrive, Eye, Maximize2, Terminal
} from 'lucide-react';
import { FileItem, FileType, FileSource } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase, generateAIImage } from './services/geminiService';
import { fetchUserRepos, mapGithubToFiles, fetchRepoContents, fetchRawGithubContent } from './services/githubService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'gallery'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);

  // Dynamic Loading States
  const [isLoadingContent, setIsLoadingContent] = useState(false);
  const [githubUsers, setGithubUsers] = useState<string[]>(['jocall3']);

  // UI Panels
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [isStudioOpen, setIsStudioOpen] = useState(false);
  const [previewFile, setPreviewFile] = useState<FileItem | null>(null);
  const [previewContent, setPreviewContent] = useState<string | null>(null);

  // AI Logic
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);
  const [studioPrompt, setStudioPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  // Sync Initial Users
  useEffect(() => {
    githubUsers.forEach(user => syncUserRepos(user));
  }, []);

  const filteredFiles = useMemo(() => {
    let base = files;
    if (aiResults) base = files.filter(f => aiResults.includes(f.id));
    else if (searchQuery && !isSearching) {
      base = files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    } else {
      base = files.filter(f => f.parentId === currentFolderId);
    }

    if (viewMode === 'gallery') {
      return base.filter(f => f.type === FileType.IMAGE);
    }
    return base;
  }, [files, currentFolderId, searchQuery, aiResults, isSearching, viewMode]);

  const syncUserRepos = async (username: string) => {
    setIsLoadingContent(true);
    const repos = await fetchUserRepos(username);
    const mapped = mapGithubToFiles(repos, `gh-${username}`, username, "Repositories");

    // Add the user's root folder if not exists
    const userFolder: FileItem = {
      id: `gh-${username}`,
      name: `${username} (GitHub)`,
      type: FileType.FOLDER,
      size: null,
      lastModified: new Date().toLocaleDateString(),
      parentId: 'root',
      source: 'github',
      githubOwner: username
    };

    setFiles(prev => {
      const others = prev.filter(f => !(f.source === 'github' && f.githubOwner === username));
      return [...others, userFolder, ...mapped];
    });
    setIsLoadingContent(false);
  };

  const handleFolderClick = async (file: FileItem) => {
    if (file.type !== FileType.FOLDER) return;

    // If it's a GitHub folder and we haven't loaded its contents yet
    if (file.source === 'github' && file.githubOwner && file.githubRepo) {
      const existingChildren = files.some(f => f.parentId === file.id);
      if (!existingChildren) {
        setIsLoadingContent(true);
        // Calculate relative path for GitHub API
        // For repos, path is "", for nested, we'd need to track full path
        const ghContents = await fetchRepoContents(file.githubOwner, file.githubRepo, file.name === file.githubRepo ? "" : file.name);
        const mapped = mapGithubToFiles(ghContents, file.id, file.githubOwner, file.githubRepo);
        setFiles(prev => [...prev, ...mapped]);
        setIsLoadingContent(false);
      }
    }

    setPath([...path, file.id]);
    setSelectedIds([]);
    setAiResults(null);
  };

  const openFileViewer = async (file: FileItem) => {
    setPreviewFile(file);
    setPreviewContent(null);
    setIsLoadingContent(true);

    if (file.type === FileType.IMAGE) {
      setPreviewContent(file.content || "");
    } else if (file.source === 'github' && file.content) {
      // file.content stores the download_url for GitHub files
      const text = await fetchRawGithubContent(file.content);
      setPreviewContent(text);
      // Automatically index for AI if not done
      if (!file.aiSummary) indexExistingFile(file, text);
    } else {
      setPreviewContent(file.content || "No preview available.");
    }
    setIsLoadingContent(false);
  };

  const indexExistingFile = async (file: FileItem, actualContent: string) => {
    const res = await indexFile({ ...file, content: actualContent });
    setFiles(p => p.map(f => f.id === file.id ? { ...f, aiSummary: res.summary, aiKeywords: res.keywords } : f));
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) {
      setAiResults(null);
      return;
    }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const handleGenerateImage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studioPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const result = await generateAIImage(studioPrompt);
      const newFile: FileItem = {
        id: `ai-${Date.now()}`,
        name: `Creation_${Math.floor(Math.random()*1000)}.png`,
        type: FileType.IMAGE,
        size: result.dataUrl.length,
        lastModified: new Date().toLocaleDateString(),
        parentId: 'ai-gallery',
        source: 'ai',
        content: result.dataUrl,
        mimeType: 'image/png',
        aiSummary: studioPrompt,
        aiKeywords: ['generated', 'ai-art', 'gemini-2.5-flash']
      };
      setFiles(prev => [...prev, newFile]);
      setStudioPrompt('');
      setIsStudioOpen(false);
      setCurrentNav('ai-gallery');
      setPath([]);
    } catch (err) {
      alert("AI generation failed. Please try a different prompt.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;
    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          source: 'local',
          content,
          mimeType: file.type,
          extension: file.name.split('.').pop()
        };
        setFiles(prev => [...prev, newFile]);
        const indexRes = await indexFile(newFile);
        setFiles(p => p.map(f => f.id === newFile.id ? { ...f, aiSummary: indexRes.summary, aiKeywords: indexRes.keywords } : f));
      };
      file.type.startsWith('text/') ? reader.readAsText(file) : reader.readAsDataURL(file);
    });
  };

  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;
    const msg = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: msg }]);
    setIsBrainThinking(true);
    const res = await queryKnowledgeBase(msg, files);
    setBrainChat(prev => [...prev, { role: 'ai', text: res }]);
    setIsBrainThinking(false);
  };

  const selectedFile = useMemo(() => files.find(f => f.id === selectedIds[0]), [selectedIds, files]);

  return (
    <div className="flex h-screen w-full bg-[#f8f9fa] select-none overflow-hidden relative font-sans text-[#3c4043]">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Sidebar */}
      <aside className="w-72 border-r border-gray-200 flex flex-col bg-white z-10 shrink-0">
        <div className="p-8">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <HardDrive size={28} />
            </div>
            <div>
              <div className="font-black text-2xl tracking-tighter text-gray-900 leading-none">OMNI</div>
              <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mt-1">File System</div>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 space-y-8">
          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Workspace</div>
            {NAV_ITEMS.filter(i => i.section !== 'trash').map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${
                  currentNav === item.id && path.length === 0 ? 'bg-blue-50 text-[#1a73e8]' : 'hover:bg-gray-50 text-gray-500'
                }`}
              >
                {item.icon} {item.label}
              </button>
            ))}
            <button
                onClick={() => { setCurrentNav('ai-gallery'); setPath([]); setAiResults(null); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${
                  currentNav === 'ai-gallery' ? 'bg-purple-50 text-purple-600' : 'hover:bg-gray-50 text-gray-500'
                }`}
              >
                <Palette size={18} /> AI Creations
              </button>
          </div>

          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 flex justify-between items-center">
              <span>Sync Hub</span>
              <button onClick={() => {
                const u = prompt("Add GitHub username:");
                if(u) { setGithubUsers([...githubUsers, u]); syncUserRepos(u); }
              }} className="hover:text-blue-600"><UserPlus size={14}/></button>
            </div>
            {githubUsers.map(user => (
              <button
                key={user}
                onClick={() => { setCurrentNav(`gh-${user}`); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${
                  currentNav === `gh-${user}` ? 'bg-indigo-50 text-indigo-600' : 'hover:bg-gray-50 text-gray-500'
                }`}
              >
                <Github size={18}/> {user}
              </button>
            ))}
          </div>

          <div className="pt-4 px-2">
             <button 
               onClick={() => setIsStudioOpen(true)}
               className="w-full flex items-center justify-between p-4 rounded-[24px] bg-gradient-to-br from-indigo-600 to-purple-700 text-white shadow-xl hover:scale-[1.02] transition-all group active:scale-95"
             >
                <div className="flex items-center gap-3">
                  <Sparkles size={20} className="group-hover:animate-spin-slow" />
                  <span className="font-black text-xs uppercase tracking-wider">AI Studio</span>
                </div>
                <ChevronRight size={16} className="opacity-50" />
             </button>
          </div>
        </div>

        <div className="p-8 border-t border-gray-100 flex items-center gap-3">
          {isLoadingContent && (
            <>
              <Loader2 size={16} className="animate-spin text-blue-500" />
              <span className="text-[10px] font-bold text-blue-500 uppercase tracking-widest">Syncing Cloud...</span>
            </>
          )}
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-2xl relative z-0">
        <header className="h-24 flex items-center justify-between px-10 border-b border-gray-100 bg-white/90 backdrop-blur-xl sticky top-0 z-20">
          <div className="flex items-center gap-6 min-w-0">
