            <div className="flex items-center gap-2 overflow-hidden">
              <span className="font-black text-2xl text-gray-900 tracking-tight">{NAV_ITEMS.find(n => n.id === currentNav)?.label || currentNav.replace('gh-', '')}</span>
              {path.map((folderId) => (
                <React.Fragment key={folderId}>
                  <ChevronRight size={20} className="text-gray-200 shrink-0" />
                  <span className="font-bold text-gray-400 text-lg whitespace-nowrap">{files.find(f => f.id === folderId)?.name}</span>
                </React.Fragment>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center bg-gray-100 rounded-[24px] px-6 py-3 w-96 focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-50 transition-all border border-transparent focus-within:border-blue-100 group">
              <Search size={18} className="text-gray-400 mr-4 group-focus-within:text-blue-500 transition-colors" />
              <input 
                type="text"
                placeholder="Deep Semantic Search..."
                className="bg-transparent border-none outline-none text-sm w-full font-bold placeholder:text-gray-400"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
              />
            </div>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : viewMode === 'grid' ? 'gallery' : 'list')}
