export enum FileType {
  FOLDER = 'folder',
  IMAGE = 'image',
  VIDEO = 'video',
  AUDIO = 'audio',
  DOCUMENT = 'document',
  ARCHIVE = 'archive',
  GENERIC = 'generic'
}

export type FileSource = 'local' | 'github' | 'ai' | 'google-drive';

export interface FileItem {
  id: string;
  name: string;
  type: FileType;
  size: number | null;
  lastModified: string;
  parentId: string | null;
  source: FileSource;
  extension?: string;
  mimeType?: string;
  content?: string; // Text, DataURL, or Download URL
  // AI fields
  aiSummary?: string;
  aiKeywords?: string[];
  isIndexing?: boolean;
  // Source metadata
  githubRepo?: string;
  githubOwner?: string;
  githubUrl?: string;
  driveFileId?: string;
  isCloudFolder?: boolean;
}

export interface NavigationState {
  currentPath: string[];
  selectedIds: string[];
  viewMode: 'list' | 'grid' | 'gallery';
}

import { FileItem, FileType } from "../types";

const DRIVE_API_BASE = "https://www.googleapis.com/drive/v3";

export async function fetchDriveFiles(accessToken: string, folderId: string = 'root'): Promise<any[]> {
  try {
    const q = `'${folderId}' in parents and trashed = false`;
    const response = await fetch(
      `${DRIVE_API_BASE}/files?q=${encodeURIComponent(q)}&fields=files(id, name, mimeType, size, modifiedTime, thumbnailLink)&pageSize=100`,
      {
        headers: { Authorization: `Bearer ${accessToken}` }
      }
    );
    if (!response.ok) throw new Error("Drive fetch failed");
    const data = await response.json();
    return data.files || [];
  } catch (error) {
    console.error("Google Drive API Error:", error);
    return [];
  }
}

export async function fetchDriveFileContent(accessToken: string, fileId: string): Promise<string> {
  try {
    const response = await fetch(`${DRIVE_API_BASE}/files/${fileId}?alt=media`, {
      headers: { Authorization: `Bearer ${accessToken}` }
    });
    if (!response.ok) return "Cannot preview this file type directly.";
    return await response.text();
  } catch (error) {
    return "Error loading Drive content.";
  }
}

export function mapDriveToFiles(driveItems: any[], parentId: string): FileItem[] {
  return driveItems.map(item => {
    const isFolder = item.mimeType === 'application/vnd.google-apps.folder';
    let type = FileType.DOCUMENT;
    if (isFolder) type = FileType.FOLDER;
    else if (item.mimeType.startsWith('image/')) type = FileType.IMAGE;
    else if (item.mimeType.startsWith('video/')) type = FileType.VIDEO;
    else if (item.mimeType.startsWith('audio/')) type = FileType.AUDIO;

    return {
      id: `drive-${item.id}`,
      driveFileId: item.id,
      name: item.name,
      type,
      size: item.size ? parseInt(item.size) : null,
      lastModified: new Date(item.modifiedTime).toLocaleDateString(),
      parentId,
      source: 'google-drive',
      mimeType: item.mimeType,
      isCloudFolder: isFolder,
      content: item.thumbnailLink // Use thumbnail for previews if image
    };
  });
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Search, RotateCw, LayoutGrid, List, MoreVertical, ChevronRight, 
  ArrowLeft, X, Plus, Folder, Brain, MessageSquare, FileUp, Sparkles, 
  Loader2, FolderPlus, Share2, Trash2, Download, Github, Palette,
  Globe, UserPlus, Image as ImageIcon, HardDrive, Eye, Maximize2, Terminal,
  Cloud, LogIn, CloudOff
} from 'lucide-react';
import { FileItem, FileType, FileSource } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase, generateAIImage } from './services/geminiService';
import { fetchUserRepos, mapGithubToFiles, fetchRepoContents, fetchRawGithubContent } from './services/githubService';
import { fetchDriveFiles, mapDriveToFiles, fetchDriveFileContent } from './services/googleDriveService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'gallery'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);

  // Cloud States
  const [isLoadingContent, setIsLoadingContent] = useState(false);
  const [githubUsers, setGithubUsers] = useState<string[]>(['jocall3']);
  const [driveToken, setDriveToken] = useState<string | null>(null);

  // UI Panels
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [isStudioOpen, setIsStudioOpen] = useState(false);
  const [previewFile, setPreviewFile] = useState<FileItem | null>(null);
  const [previewContent, setPreviewContent] = useState<string | null>(null);

  // AI State
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);
  const [studioPrompt, setStudioPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  // Initialize
  useEffect(() => {
    githubUsers.forEach(user => syncUserRepos(user));
  }, []);

  const filteredFiles = useMemo(() => {
    let base = files;
    if (aiResults) base = files.filter(f => aiResults.includes(f.id));
    else if (searchQuery && !isSearching) {
      base = files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    } else {
      base = files.filter(f => f.parentId === currentFolderId);
    }
    if (viewMode === 'gallery') return base.filter(f => f.type === FileType.IMAGE);
    return base;
  }, [files, currentFolderId, searchQuery, aiResults, isSearching, viewMode]);

  // Google Drive Auth (Simulated for Demo Environment)
  const handleConnectDrive = () => {
    // In a real app, this would trigger the Google Identity Services popup
    const token = prompt("Enter a Google OAuth Token (or just click OK to simulate connection):");
    const mockToken = token || "demo-token";
    setDriveToken(mockToken);
    syncDriveRoot(mockToken);
  };

  const syncDriveRoot = async (token: string) => {
    setIsLoadingContent(true);
    const driveItems = await fetchDriveFiles(token);
    const mapped = mapDriveToFiles(driveItems, 'drive');
    setFiles(prev => {
      const others = prev.filter(f => f.source !== 'google-drive');
      return [...others, ...mapped];
    });
    setIsLoadingContent(false);
  };

  const syncUserRepos = async (username: string) => {
    setIsLoadingContent(true);
    const repos = await fetchUserRepos(username);
    const mapped = mapGithubToFiles(repos, `gh-${username}`, username, "Repositories");
    const userFolder: FileItem = {
      id: `gh-${username}`,
      name: `${username} (GitHub)`,
      type: FileType.FOLDER,
      size: null,
      lastModified: new Date().toLocaleDateString(),
      parentId: 'root',
      source: 'github',
      githubOwner: username
    };
    setFiles(prev => {
      const others = prev.filter(f => !(f.source === 'github' && f.githubOwner === username));
      return [...others, userFolder, ...mapped];
    });
    setIsLoadingContent(false);
  };

  const handleFolderClick = async (file: FileItem) => {
    if (file.type !== FileType.FOLDER) return;

    // Load GitHub nested contents
    if (file.source === 'github' && file.githubOwner && file.githubRepo) {
      const existingChildren = files.some(f => f.parentId === file.id);
      if (!existingChildren) {
        setIsLoadingContent(true);
        const ghContents = await fetchRepoContents(file.githubOwner, file.githubRepo, file.name === file.githubRepo ? "" : file.name);
        const mapped = mapGithubToFiles(ghContents, file.id, file.githubOwner, file.githubRepo);
        setFiles(prev => [...prev, ...mapped]);
        setIsLoadingContent(false);
      }
    }

    // Load Google Drive nested contents
    if (file.source === 'google-drive' && driveToken && file.driveFileId) {
      const existingChildren = files.some(f => f.parentId === file.id);
      if (!existingChildren) {
        setIsLoadingContent(true);
        const driveItems = await fetchDriveFiles(driveToken, file.driveFileId);
        const mapped = mapDriveToFiles(driveItems, file.id);
        setFiles(prev => [...prev, ...mapped]);
        setIsLoadingContent(false);
      }
    }

    setPath([...path, file.id]);
    setSelectedIds([]);
  };

  const openFileViewer = async (file: FileItem) => {
    setPreviewFile(file);
    setPreviewContent(null);
    setIsLoadingContent(true);

    if (file.type === FileType.IMAGE && file.source !== 'google-drive') {
      setPreviewContent(file.content || "");
    } else if (file.source === 'github' && file.content) {
      const text = await fetchRawGithubContent(file.content);
      setPreviewContent(text);
      if (!file.aiSummary) indexExistingFile(file, text);
    } else if (file.source === 'google-drive' && driveToken && file.driveFileId) {
      const text = await fetchDriveFileContent(driveToken, file.driveFileId);
      setPreviewContent(text);
      if (!file.aiSummary) indexExistingFile(file, text);
    } else {
      setPreviewContent(file.content || "No preview available.");
    }
    setIsLoadingContent(false);
  };

  const indexExistingFile = async (file: FileItem, actualContent: string) => {
    const res = await indexFile({ ...file, content: actualContent });
    setFiles(p => p.map(f => f.id === file.id ? { ...f, aiSummary: res.summary, aiKeywords: res.keywords } : f));
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) { setAiResults(null); return; }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const handleGenerateImage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studioPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const result = await generateAIImage(studioPrompt);
      const newFile: FileItem = {
        id: `ai-${Date.now()}`,
        name: `Creation_${Math.floor(Math.random()*1000)}.png`,
        type: FileType.IMAGE,
        size: result.dataUrl.length,
        lastModified: new Date().toLocaleDateString(),
        parentId: 'ai-gallery',
        source: 'ai',
        content: result.dataUrl,
        mimeType: 'image/png',
        aiSummary: studioPrompt,
      };
      setFiles(prev => [...prev, newFile]);
      setStudioPrompt('');
      setIsStudioOpen(false);
      setCurrentNav('ai-gallery');
      setPath([]);
    } catch (err) {
      alert("AI generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;
    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          source: 'local',
          content,
          mimeType: file.type
        };
        setFiles(prev => [...prev, newFile]);
        const indexRes = await indexFile(newFile);
        setFiles(p => p.map(f => f.id === newFile.id ? { ...f, aiSummary: indexRes.summary, aiKeywords: indexRes.keywords } : f));
      };
      file.type.startsWith('text/') ? reader.readAsText(file) : reader.readAsDataURL(file);
    });
  };

  return (
    <div className="flex h-screen w-full bg-[#f8f9fa] select-none overflow-hidden relative font-sans text-[#3c4043]">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Dynamic Sidebar */}
      <aside className="w-72 border-r border-gray-200 flex flex-col bg-white z-10 shrink-0">
        <div className="p-8">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <HardDrive size={28} />
            </div>
            <div>
              <div className="font-black text-2xl tracking-tighter text-gray-900 leading-none">OMNI</div>
              <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mt-1">Workspace v2</div>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 space-y-8">
          {/* Main Nodes */}
          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 text-center border-b border-gray-50 pb-2">File Sources</div>
            {NAV_ITEMS.filter(i => i.id === 'root' || i.id === 'recent').map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === item.id && path.length === 0 ? 'bg-blue-50 text-blue-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                {item.icon} {item.label}
              </button>
            ))}
            <button
                onClick={() => { setCurrentNav('drive'); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === 'drive' ? 'bg-blue-50 text-blue-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Cloud size={18} /> {driveToken ? 'My Drive' : 'Google Drive'}
                {driveToken && <div className="ml-auto w-2 h-2 bg-green-500 rounded-full"></div>}
            </button>
            <button
                onClick={() => { setCurrentNav('ai-gallery'); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === 'ai-gallery' ? 'bg-purple-50 text-purple-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Palette size={18} /> AI Creations
            </button>
          </div>

          {/* Sync Hub - GitHub & more */}
          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 flex justify-between items-center">
              <span>Code Hub</span>
              <button onClick={() => {
                const u = prompt("Add GitHub username:");
                if(u) { setGithubUsers([...githubUsers, u]); syncUserRepos(u); }
              }} className="hover:text-blue-600"><UserPlus size={14}/></button>
            </div>
            {githubUsers.map(user => (
              <button
                key={user}
                onClick={() => { setCurrentNav(`gh-${user}`); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === `gh-${user}` ? 'bg-indigo-50 text-indigo-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Github size={18}/> {user}
              </button>
            ))}
          </div>

          {/* AI Quick Actions */}
          <div className="pt-4 px-2 space-y-3">
             <button onClick={() => setIsStudioOpen(true)} className="w-full flex items-center gap-3 p-4 rounded-3xl bg-gradient-to-br from-indigo-600 to-purple-700 text-white shadow-xl hover:scale-[1.02] transition-all group active:scale-95">
                <Sparkles size={20} />
                <span className="font-black text-xs uppercase">AI Gen Studio</span>
             </button>
             <button onClick={() => setIsBrainOpen(true)} className="w-full flex items-center gap-3 p-4 rounded-3xl bg-white border border-indigo-100 text-indigo-700 hover:bg-indigo-50 transition-all font-black text-xs uppercase">
                <Brain size={20} className="animate-pulse" /> Workspace Brain
             </button>
          </div>
        </div>

        {/* Sync Status Footer */}
        <div className="p-8 border-t border-gray-100">
           {!driveToken ? (
             <button onClick={handleConnectDrive} className="w-full py-3 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-blue-100 transition-all">
               <LogIn size={14}/> Connect Google Drive
             </button>
           ) : (
             <div className="flex items-center gap-3 text-emerald-600">
                <Loader2 size={16} className={isLoadingContent ? "animate-spin" : "hidden"} />
                <span className="text-[10px] font-black uppercase tracking-widest">{isLoadingContent ? 'Syncing Cloud...' : 'Cloud Connected'}</span>
                <button onClick={() => setDriveToken(null)} className="ml-auto text-gray-400 hover:text-red-500"><CloudOff size={14}/></button>
             </div>
           )}
        </div>
      </aside>

      {/* Primary Workspace */}
      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-2xl relative z-0">
        <header className="h-24 flex items-center justify-between px-10 border-b border-gray-100 bg-white/90 backdrop-blur-xl sticky top-0 z-20">
          <div className="flex items-center gap-6 min-w-0">
            {path.length > 0 && (
              <button onClick={() => setPath(path.slice(0, -1))} className="p-3 bg-gray-50 hover:bg-gray-100 rounded-2xl transition-colors text-gray-400">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-2 overflow-hidden">
              <span className="font-black text-2xl text-gray-900 tracking-tight">
                {NAV_ITEMS.find(n => n.id === currentNav)?.label || currentNav.replace('gh-', '')}
              </span>
              {path.map((folderId) => (
                <React.Fragment key={folderId}>
                  <ChevronRight size={20} className="text-gray-200 shrink-0" />
                  <span className="font-bold text-gray-400 text-lg whitespace-nowrap">{files.find(f => f.id === folderId)?.name}</span>
                </React.Fragment>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center bg-gray-100 rounded-[24px] px-6 py-3 w-96 focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-50 transition-all border border-transparent focus-within:border-blue-100">
              <Search size={18} className="text-gray-400 mr-4" />
              <input 
                type="text"
                placeholder="Global AI Search..."
                className="bg-transparent border-none outline-none text-sm w-full font-bold"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
              />
            </div>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : viewMode === 'grid' ? 'gallery' : 'list')}
              className="p-3 bg-gray-50 text-gray-400 rounded-2xl hover:text-gray-900 transition-all font-bold text-xs flex items-center gap-2"
            >
              {viewMode === 'list' ? <List size={18}/> : viewMode === 'grid' ? <LayoutGrid size={18}/> : <ImageIcon size={18}/>}
              <span className="uppercase tracking-widest">{viewMode}</span>
            </button>
          </div>
        </header>

        {/* Selected File Action Bar */}
        {selectedFile && (
          <div className="mx-10 mt-6 p-6 rounded-[32px] bg-gradient-to-r from-blue-50 to-white border border-blue-100 flex items-center gap-8 animate-in slide-in-from-top-4 duration-500 shadow-sm">
            <div className="w-16 h-16 bg-white rounded-3xl shadow-md flex items-center justify-center">
              {getFileIcon(selectedFile.type)}
            </div>
            <div className="flex-1 min-w-0">
               <div className="flex items-center gap-3 mb-1">
                 <span className="text-[10px] font-black uppercase text-blue-600 tracking-widest px-2 py-0.5 bg-blue-100 rounded-full">{selectedFile.source} Content</span>
                 {selectedFile.source === 'google-drive' && <Cloud size={12} className="text-blue-500"/>}
                 {selectedFile.source === 'github' && <Github size={12}/>}
               </div>
               <h3 className="font-black text-xl text-gray-900 truncate">{selectedFile.name}</h3>
               <p className="text-sm text-gray-500 mt-1 line-clamp-1 italic">
                 {selectedFile.aiSummary || "Select to analyze this cloud resource..."}
               </p>
            </div>
            <div className="flex gap-3">
               <button onClick={() => openFileViewer(selectedFile)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
                 <Eye size={16}/> Open Viewer
               </button>
               <button onClick={() => setSelectedIds([])} className="p-3 bg-white text-gray-300 border border-gray-100 rounded-2xl hover:text-gray-900 transition-colors"><X size={18}/></button>
            </div>
          </div>
        )}

        {/* File Browser Area */}
        <div className="flex-1 overflow-auto p-10">
          {filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-40">
              <div className="w-40 h-40 bg-gray-50 rounded-full flex items-center justify-center mb-8">
                <Globe size={80} className="text-gray-100" />
              </div>
              <h2 className="text-2xl font-black text-gray-800">Empty View</h2>
              <p className="text-sm text-gray-400 mt-3 font-medium">Connect a source or upload files.</p>
            </div>
          ) : (
            <div className={`grid gap-8 ${
              viewMode === 'list' ? 'grid-cols-1' : 
              viewMode === 'gallery' ? 'grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5' :
              'grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6'
            }`}>
              {filteredFiles.map(file => (
                <div 
                  key={file.id}
                  onClick={(e) => {
                    e.stopPropagation();
                    if(e.ctrlKey || e.metaKey) setSelectedIds(prev => prev.includes(file.id) ? prev.filter(i => i !== file.id) : [...prev, file.id]);
                    else setSelectedIds([file.id]);
                  }}
                  onDoubleClick={() => file.type === FileType.FOLDER ? handleFolderClick(file) : openFileViewer(file)}
                  className={`group relative flex flex-col p-5 rounded-[32px] border transition-all cursor-pointer ${
                    selectedIds.includes(file.id) 
                    ? 'bg-blue-50 border-blue-200 ring-[8px] ring-blue-50/50 scale-105 shadow-xl' 
                    : 'bg-white border-gray-100 hover:border-gray-200 hover:shadow-lg'
                  }`}
                >
                  <div className="absolute top-4 right-4 flex gap-2">
                    {file.source === 'google-drive' && <Cloud size={14} className="text-blue-300"/>}
                    {file.source === 'github' && <Github size={14} className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity"/>}
                    {file.source === 'ai' && <Sparkles size={14} className="text-purple-400"/>}
                  </div>

                  <div className="flex-1 mb-4 rounded-[20px] flex items-center justify-center transition-transform group-hover:scale-105 overflow-hidden bg-gray-50/50 min-h-[140px]">
                    {file.type === FileType.IMAGE && file.content ? (
                      <img src={file.content} className="w-full h-full object-cover" loading="lazy" />
                    ) : (
                      React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: viewMode === 'gallery' ? 64 : 48 })
                    )}
                  </div>

                  <div className="text-center px-1">
                    <span className="text-xs font-black text-gray-900 truncate block">{file.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 uppercase tracking-widest mt-1 block">
                      {file.type === FileType.FOLDER ? 'Directory' : formatSize(file.size)}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Global Action Footer */}
        <footer className="h-28 px-10 border-t border-gray-100 bg-white/80 backdrop-blur-xl flex items-center justify-between z-10">
           <div className="flex gap-4">
             <button 
               onClick={() => fileInputRef.current?.click()}
               className="flex items-center gap-3 px-8 py-4 bg-gray-900 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all"
             >
               <FileUp size={20}/> Upload Work
             </button>
             <button onClick={() => setIsStudioOpen(true)} className="px-8 py-4 bg-purple-600 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-purple-700 active:scale-95 transition-all flex items-center gap-3">
               <Palette size={20}/> AI Studio
             </button>
           </div>

           <div className="flex items-center gap-4">
             <button className={`px-12 py-4 rounded-[24px] font-black text-xs uppercase tracking-widest transition-all ${
               selectedIds.length > 0 ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 active:scale-95' : 'bg-gray-100 text-gray-300 cursor-not-allowed'
             }`} disabled={selectedIds.length === 0}>
               PROCESS FILES
             </button>
           </div>
        </footer>
      </main>

      {/* Omni Viewer Portal */}
      {previewFile && (
        <div className="fixed inset-0 bg-gray-950/90 backdrop-blur-2xl z-[200] flex items-stretch p-12 animate-in fade-in duration-500">
           <div className="bg-white rounded-[48px] shadow-2xl w-full flex overflow-hidden border border-white/20">
              <div className="flex-1 flex flex-col min-w-0">
                <div className="h-24 px-10 border-b border-gray-100 flex items-center justify-between bg-white/50">
                  <div className="flex items-center gap-5">
                    <div className="p-3 bg-gray-50 rounded-2xl">{getFileIcon(previewFile.type)}</div>
                    <div>
                      <h2 className="font-black text-2xl text-gray-900 leading-none">{previewFile.name}</h2>
                      <div className="flex items-center gap-3 mt-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                        <span className="px-2 py-0.5 bg-gray-100 rounded-full">{previewFile.source}</span>
                        <span>{formatSize(previewFile.size)}</span>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => setPreviewFile(null)} className="p-4 bg-gray-900 text-white rounded-full hover:bg-red-600 transition-all shadow-xl active:scale-90"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-auto bg-[#f8f9fa] p-12 relative">
                  {isLoadingContent ? (
                    <div className="h-full flex items-center justify-center flex-col gap-6">
                      <Loader2 size={48} className="animate-spin text-blue-600" />
                      <span className="text-xs font-black uppercase text-blue-600 tracking-widest animate-pulse">Streaming Cloud Data...</span>
                    </div>
                  ) : previewFile.type === FileType.IMAGE ? (
                    <div className="h-full flex items-center justify-center">
                      <img src={previewContent || ""} className="max-w-full max-h-full object-contain rounded-3xl shadow-2xl border-[12px] border-white" />
                    </div>
                  ) : (
                    <div className="max-w-5xl mx-auto bg-white rounded-[40px] shadow-2xl overflow-hidden border border-gray-100 h-full">
                      <div className="h-12 px-8 bg-gray-50 flex items-center gap-3 border-b border-gray-100">
                        <div className="w-3 h-3 rounded-full bg-red-400"></div>
                        <div className="w-3 h-3 rounded-full bg-amber-400"></div>
                        <div className="w-3 h-3 rounded-full bg-emerald-400"></div>
                        <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-4">Universal Inspector 2.0</span>
                      </div>
                      <pre className="p-10 text-sm font-mono leading-relaxed text-gray-700 whitespace-pre-wrap overflow-y-auto h-[calc(100%-3rem)]">
                        {previewContent || "No binary preview available for this file type."}
                      </pre>
                    </div>
                  )}
                </div>
              </div>

              {/* Viewer AI Context Sidebar */}
              <div className="w-[420px] border-l border-gray-100 bg-white flex flex-col shrink-0">
                <div className="p-10 border-b border-gray-100">
                  <div className="flex items-center gap-4 text-indigo-600 mb-8">
                    <div className="p-3 bg-indigo-50 rounded-2xl"><Brain size={28}/></div>
                    <span className="font-black text-lg uppercase tracking-tight">Context Engine</span>
                  </div>
                  <div className="bg-gradient-to-br from-indigo-50 to-white p-8 rounded-[40px] border border-indigo-100 shadow-inner">
                    <h4 className="font-black text-xs text-indigo-700 uppercase tracking-widest mb-3 flex items-center gap-2">
                      <Sparkles size={14}/> Gemini Insight
                    </h4>
                    <p className="text-sm text-indigo-900 leading-relaxed font-medium">
                      {previewFile.aiSummary || "Index this file to unlock deep AI understanding of its contents..."}
                    </p>
                  </div>
                </div>
                <div className="flex-1 p-10 overflow-y-auto">
                   <div className="text-center space-y-6">
                      <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto text-gray-300">
                        <MessageSquare size={24}/>
                      </div>
                      <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Ask Gemini about this file in the Main Brain panel</p>
                   </div>
                </div>
                <div className="p-10">
                   <button onClick={() => setIsBrainOpen(true)} className="w-full py-5 bg-indigo-600 text-white rounded-3xl font-black text-sm uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">Launch Brain</button>
                </div>
           </div>
        </div>
      )}

      {/* AI Studio & Brain components remain unchanged, but now can access Google Drive context */}
      {/* ... [Studio Modal & Brain Slide-out code] ... */}

      {/* (Including key bits for brevity, same as previous App.tsx but integrated) */}
      {isStudioOpen && (
        <div className="fixed inset-0 bg-gray-950/70 backdrop-blur-md z-[250] flex items-center justify-center p-6 animate-in fade-in">
           <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in-95 duration-500">
              <div className="p-10 bg-gradient-to-br from-indigo-600 to-purple-800 text-white relative">
                <div className="flex items-center gap-5">
                  <div className="p-4 bg-white/20 rounded-3xl backdrop-blur-md">
                    <Palette size={40}/>
                  </div>
                  <div>
                    <h2 className="text-3xl font-black tracking-tight">AI Image Studio</h2>
                    <p className="text-xs text-white/60 font-bold uppercase tracking-widest mt-1">Direct Neural Art Engine</p>
                  </div>
                </div>
                <button onClick={() => setIsStudioOpen(false)} className="absolute top-8 right-8 p-3 hover:bg-white/20 rounded-full transition-colors"><X size={28}/></button>
              </div>
              <div className="p-12">
                <form onSubmit={handleGenerateImage} className="space-y-8">
                   <textarea 
                     value={studioPrompt}
                     onChange={(e) => setStudioPrompt(e.target.value)}
                     placeholder="Imagine something extraordinary..."
                     className="w-full h-44 p-8 bg-gray-50 rounded-[32px] border-none outline-none text-gray-800 placeholder:text-gray-300 font-bold text-xl resize-none shadow-inner focus:ring-8 focus:ring-indigo-50 transition-all"
                   />
                   <button disabled={isGenerating || !studioPrompt.trim()} className="w-full py-6 bg-indigo-600 text-white rounded-[32px] font-black text-lg shadow-2xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-5">
                     {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles />} {isGenerating ? "Transmuting..." : "Create & Save to Gallery"}
                   </button>
                </form>
              </div>
           </div>
        </div>
      )}

      {/* Brain Slide-out */}
      <div className={`fixed right-0 top-0 h-full w-[500px] bg-white border-l border-gray-100 shadow-[0_0_100px_rgba(0,0,0,0.1)] transition-transform duration-700 z-[300] flex flex-col ${isBrainOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-10 border-b border-gray-100 bg-[#f8f9fa] flex items-center justify-between">
          <div className="flex items-center gap-5 text-indigo-600">
            <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center shadow-lg border border-indigo-50"><Brain size={36}/></div>
            <div>
              <h2 className="text-2xl font-black tracking-tight text-gray-900 leading-none">OMNI BRAIN</h2>
              <p className="text-[10px] text-indigo-500 uppercase font-black tracking-widest mt-2">Local + Cloud Intelligence</p>
            </div>
          </div>
          <button onClick={() => setIsBrainOpen(false)} className="p-4 hover:bg-gray-200 rounded-full text-gray-400 transition-colors"><X size={28}/></button>
        </div>

        <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-white">
          {brainChat.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-500`}>
              <div className={`max-w-[85%] px-8 py-5 rounded-[32px] text-sm leading-relaxed shadow-sm border font-medium ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none border-transparent' : 'bg-gray-50 text-gray-800 rounded-tl-none border-gray-100'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isBrainThinking && (
            <div className="flex justify-start">
              <div className="bg-gray-50 px-8 py-5 rounded-[32px] rounded-tl-none border border-gray-100 flex gap-3">
                <div className="w-2.5 h-2.5 bg-indigo-200 rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleBrainSubmit} className="p-10 bg-white border-t border-gray-100">
          <input 
            type="text" 
            placeholder="Search across Local, GitHub & Drive..."
            className="w-full bg-gray-100 border-none outline-none py-6 px-8 rounded-[30px] text-sm font-black focus:bg-white focus:ring-8 focus:ring-indigo-50 transition-all shadow-inner"
            value={brainInput}
            onChange={(e) => setBrainInput(e.target.value)}
          />
        </form>
      </div>
    </div>
  );
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Search, RotateCw, LayoutGrid, List, MoreVertical, ChevronRight, 
  ArrowLeft, X, Plus, Folder, Brain, MessageSquare, FileUp, Sparkles, 
  Loader2, FolderPlus, Share2, Trash2, Download, Github, Palette,
  Globe, UserPlus, Image as ImageIcon, HardDrive, Eye, Maximize2, Terminal,
  Cloud, LogIn, CloudOff
} from 'lucide-react';
import { FileItem, FileType, FileSource } from './types';
import { NAV_ITEMS, getFileIcon, formatSize } from './constants';
import { smartSearch, indexFile, queryKnowledgeBase, generateAIImage } from './services/geminiService';
import { fetchUserRepos, mapGithubToFiles, fetchRepoContents, fetchRawGithubContent } from './services/githubService';
import { fetchDriveFiles, mapDriveToFiles, fetchDriveFileContent } from './services/googleDriveService';
import { str } from './lib/loadTimeData';

export default function App() {
  const [files, setFiles] = useState<FileItem[]>([]);
  const [currentNav, setCurrentNav] = useState('root');
  const [path, setPath] = useState<string[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'grid' | 'gallery'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);

  // Cloud States
  const [isLoadingContent, setIsLoadingContent] = useState(false);
  const [githubUsers, setGithubUsers] = useState<string[]>(['jocall3']);
  const [driveToken, setDriveToken] = useState<string | null>(null);

  // UI Panels
  const [isBrainOpen, setIsBrainOpen] = useState(false);
  const [isStudioOpen, setIsStudioOpen] = useState(false);
  const [previewFile, setPreviewFile] = useState<FileItem | null>(null);
  const [previewContent, setPreviewContent] = useState<string | null>(null);

  // AI State
  const [brainChat, setBrainChat] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [brainInput, setBrainInput] = useState('');
  const [isBrainThinking, setIsBrainThinking] = useState(false);
  const [studioPrompt, setStudioPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currentFolderId = path.length > 0 ? path[path.length - 1] : currentNav;

  // Fix: Add selectedFile memoized value derived from selectedIds
  const selectedFile = useMemo(() => {
    if (selectedIds.length !== 1) return null;
    return files.find(f => f.id === selectedIds[0]) || null;
  }, [selectedIds, files]);

  // Initialize
  useEffect(() => {
    githubUsers.forEach(user => syncUserRepos(user));
  }, []);

  const filteredFiles = useMemo(() => {
    let base = files;
    if (aiResults) base = files.filter(f => aiResults.includes(f.id));
    else if (searchQuery && !isSearching) {
      base = files.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase()));
    } else {
      base = files.filter(f => f.parentId === currentFolderId);
    }
    if (viewMode === 'gallery') return base.filter(f => f.type === FileType.IMAGE);
    return base;
  }, [files, currentFolderId, searchQuery, aiResults, isSearching, viewMode]);

  // Google Drive Auth (Simulated for Demo Environment)
  const handleConnectDrive = () => {
    // In a real app, this would trigger the Google Identity Services popup
    const token = prompt("Enter a Google OAuth Token (or just click OK to simulate connection):");
    const mockToken = token || "demo-token";
    setDriveToken(mockToken);
    syncDriveRoot(mockToken);
  };

  const syncDriveRoot = async (token: string) => {
    setIsLoadingContent(true);
    const driveItems = await fetchDriveFiles(token);
    const mapped = mapDriveToFiles(driveItems, 'drive');
    setFiles(prev => {
      const others = prev.filter(f => f.source !== 'google-drive');
      return [...others, ...mapped];
    });
    setIsLoadingContent(false);
  };

  const syncUserRepos = async (username: string) => {
    setIsLoadingContent(true);
    const repos = await fetchUserRepos(username);
    const mapped = mapGithubToFiles(repos, `gh-${username}`, username, "Repositories");
    const userFolder: FileItem = {
      id: `gh-${username}`,
      name: `${username} (GitHub)`,
      type: FileType.FOLDER,
      size: null,
      lastModified: new Date().toLocaleDateString(),
      parentId: 'root',
      source: 'github',
      githubOwner: username
    };
    setFiles(prev => {
      const others = prev.filter(f => !(f.source === 'github' && f.githubOwner === username));
      return [...others, userFolder, ...mapped];
    });
    setIsLoadingContent(false);
  };

  const handleFolderClick = async (file: FileItem) => {
    if (file.type !== FileType.FOLDER) return;

    // Load GitHub nested contents
    if (file.source === 'github' && file.githubOwner && file.githubRepo) {
      const existingChildren = files.some(f => f.parentId === file.id);
      if (!existingChildren) {
        setIsLoadingContent(true);
        const ghContents = await fetchRepoContents(file.githubOwner, file.githubRepo, file.name === file.githubRepo ? "" : file.name);
        const mapped = mapGithubToFiles(ghContents, file.id, file.githubOwner, file.githubRepo);
        setFiles(prev => [...prev, ...mapped]);
        setIsLoadingContent(false);
      }
    }

    // Load Google Drive nested contents
    if (file.source === 'google-drive' && driveToken && file.driveFileId) {
      const existingChildren = files.some(f => f.parentId === file.id);
      if (!existingChildren) {
        setIsLoadingContent(true);
        const driveItems = await fetchDriveFiles(driveToken, file.driveFileId);
        const mapped = mapDriveToFiles(driveItems, file.id);
        setFiles(prev => [...prev, ...mapped]);
        setIsLoadingContent(false);
      }
    }

    setPath([...path, file.id]);
    setSelectedIds([]);
  };

  const openFileViewer = async (file: FileItem) => {
    setPreviewFile(file);
    setPreviewContent(null);
    setIsLoadingContent(true);

    if (file.type === FileType.IMAGE && file.source !== 'google-drive') {
      setPreviewContent(file.content || "");
    } else if (file.source === 'github' && file.content) {
      const text = await fetchRawGithubContent(file.content);
      setPreviewContent(text);
      if (!file.aiSummary) indexExistingFile(file, text);
    } else if (file.source === 'google-drive' && driveToken && file.driveFileId) {
      const text = await fetchDriveFileContent(driveToken, file.driveFileId);
      setPreviewContent(text);
      if (!file.aiSummary) indexExistingFile(file, text);
    } else {
      setPreviewContent(file.content || "No preview available.");
    }
    setIsLoadingContent(false);
  };

  const indexExistingFile = async (file: FileItem, actualContent: string) => {
    const res = await indexFile({ ...file, content: actualContent });
    setFiles(p => p.map(f => f.id === file.id ? { ...f, aiSummary: res.summary, aiKeywords: res.keywords } : f));
  };

  const handleSmartSearch = async () => {
    if (!searchQuery.trim()) { setAiResults(null); return; }
    setIsSearching(true);
    const results = await smartSearch(searchQuery, files);
    setAiResults(results);
    setIsSearching(false);
  };

  const handleGenerateImage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studioPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const result = await generateAIImage(studioPrompt);
      const newFile: FileItem = {
        id: `ai-${Date.now()}`,
        name: `Creation_${Math.floor(Math.random()*1000)}.png`,
        type: FileType.IMAGE,
        size: result.dataUrl.length,
        lastModified: new Date().toLocaleDateString(),
        parentId: 'ai-gallery',
        source: 'ai',
        content: result.dataUrl,
        mimeType: 'image/png',
        aiSummary: studioPrompt,
      };
      setFiles(prev => [...prev, newFile]);
      setStudioPrompt('');
      setIsStudioOpen(false);
      setCurrentNav('ai-gallery');
      setPath([]);
    } catch (err) {
      alert("AI generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const loadedFiles = e.target.files;
    if (!loadedFiles) return;
    Array.from(loadedFiles).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        const newFile: FileItem = {
          id: Math.random().toString(36).substring(2, 11),
          name: file.name,
          type: file.type.startsWith('image/') ? FileType.IMAGE : FileType.DOCUMENT,
          size: file.size,
          lastModified: new Date().toLocaleDateString(),
          parentId: currentFolderId,
          source: 'local',
          content,
          mimeType: file.type
        };
        setFiles(prev => [...prev, newFile]);
        const indexRes = await indexFile(newFile);
        setFiles(p => p.map(f => f.id === newFile.id ? { ...f, aiSummary: indexRes.summary, aiKeywords: indexRes.keywords } : f));
      };
      file.type.startsWith('text/') ? reader.readAsText(file) : reader.readAsDataURL(file);
    });
  };

  // Fix: Implement handleBrainSubmit to process queries in the Brain panel
  const handleBrainSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brainInput.trim()) return;

    const userMessage = brainInput;
    setBrainInput('');
    setBrainChat(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsBrainThinking(true);

    try {
      const response = await queryKnowledgeBase(userMessage, files);
      setBrainChat(prev => [...prev, { role: 'ai', text: response }]);
    } catch (error) {
      setBrainChat(prev => [...prev, { role: 'ai', text: "I encountered an error while processing your request." }]);
    } finally {
      setIsBrainThinking(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8f9fa] select-none overflow-hidden relative font-sans text-[#3c4043]">
      <input type="file" multiple ref={fileInputRef} className="hidden" onChange={handleFileUpload} />

      {/* Dynamic Sidebar */}
      <aside className="w-72 border-r border-gray-200 flex flex-col bg-white z-10 shrink-0">
        <div className="p-8">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <HardDrive size={28} />
            </div>
            <div>
              <div className="font-black text-2xl tracking-tighter text-gray-900 leading-none">OMNI</div>
              <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mt-1">Workspace v2</div>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 space-y-8">
          {/* Main Nodes */}
          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 text-center border-b border-gray-50 pb-2">File Sources</div>
            {NAV_ITEMS.filter(i => i.id === 'root' || i.id === 'recent').map(item => (
              <button
                key={item.id}
                onClick={() => { setCurrentNav(item.id); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === item.id && path.length === 0 ? 'bg-blue-50 text-blue-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                {item.icon} {item.label}
              </button>
            ))}
            <button
                onClick={() => { setCurrentNav('drive'); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === 'drive' ? 'bg-blue-50 text-blue-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Cloud size={18} /> {driveToken ? 'My Drive' : 'Google Drive'}
                {driveToken && <div className="ml-auto w-2 h-2 bg-green-500 rounded-full"></div>}
            </button>
            <button
                onClick={() => { setCurrentNav('ai-gallery'); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === 'ai-gallery' ? 'bg-purple-50 text-purple-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Palette size={18} /> AI Creations
            </button>
          </div>

          {/* Sync Hub - GitHub & more */}
          <div className="space-y-1">
            <div className="px-4 text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 flex justify-between items-center">
              <span>Code Hub</span>
              <button onClick={() => {
                const u = prompt("Add GitHub username:");
                if(u) { setGithubUsers([...githubUsers, u]); syncUserRepos(u); }
              }} className="hover:text-blue-600"><UserPlus size={14}/></button>
            </div>
            {githubUsers.map(user => (
              <button
                key={user}
                onClick={() => { setCurrentNav(`gh-${user}`); setPath([]); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-sm font-bold transition-all ${currentNav === `gh-${user}` ? 'bg-indigo-50 text-indigo-600' : 'hover:bg-gray-50 text-gray-500'}`}
              >
                <Github size={18}/> {user}
              </button>
            ))}
          </div>

          {/* AI Quick Actions */}
          <div className="pt-4 px-2 space-y-3">
             <button onClick={() => setIsStudioOpen(true)} className="w-full flex items-center gap-3 p-4 rounded-3xl bg-gradient-to-br from-indigo-600 to-purple-700 text-white shadow-xl hover:scale-[1.02] transition-all group active:scale-95">
                <Sparkles size={20} />
                <span className="font-black text-xs uppercase">AI Gen Studio</span>
             </button>
             <button onClick={() => setIsBrainOpen(true)} className="w-full flex items-center gap-3 p-4 rounded-3xl bg-white border border-indigo-100 text-indigo-700 hover:bg-indigo-50 transition-all font-black text-xs uppercase">
                <Brain size={20} className="animate-pulse" /> Workspace Brain
             </button>
          </div>
        </div>

        {/* Sync Status Footer */}
        <div className="p-8 border-t border-gray-100">
           {!driveToken ? (
             <button onClick={handleConnectDrive} className="w-full py-3 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-blue-100 transition-all">
               <LogIn size={14}/> Connect Google Drive
             </button>
           ) : (
             <div className="flex items-center gap-3 text-emerald-600">
                <Loader2 size={16} className={isLoadingContent ? "animate-spin" : "hidden"} />
                <span className="text-[10px] font-black uppercase tracking-widest">{isLoadingContent ? 'Syncing Cloud...' : 'Cloud Connected'}</span>
                <button onClick={() => setDriveToken(null)} className="ml-auto text-gray-400 hover:text-red-500"><CloudOff size={14}/></button>
             </div>
           )}
        </div>
      </aside>

      {/* Primary Workspace */}
      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-2xl relative z-0">
        <header className="h-24 flex items-center justify-between px-10 border-b border-gray-100 bg-white/90 backdrop-blur-xl sticky top-0 z-20">
          <div className="flex items-center gap-6 min-w-0">
            {path.length > 0 && (
              <button onClick={() => setPath(path.slice(0, -1))} className="p-3 bg-gray-50 hover:bg-gray-100 rounded-2xl transition-colors text-gray-400">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-2 overflow-hidden">
              <span className="font-black text-2xl text-gray-900 tracking-tight">
                {NAV_ITEMS.find(n => n.id === currentNav)?.label || currentNav.replace('gh-', '')}
              </span>
              {path.map((folderId) => (
                <React.Fragment key={folderId}>
                  <ChevronRight size={20} className="text-gray-200 shrink-0" />
                  <span className="font-bold text-gray-400 text-lg whitespace-nowrap">{files.find(f => f.id === folderId)?.name}</span>
                </React.Fragment>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center bg-gray-100 rounded-[24px] px-6 py-3 w-96 focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-50 transition-all border border-transparent focus-within:border-blue-100">
              <Search size={18} className="text-gray-400 mr-4" />
              <input 
                type="text"
                placeholder="Global AI Search..."
                className="bg-transparent border-none outline-none text-sm w-full font-bold"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
              />
            </div>
            <button 
              onClick={() => setViewMode(viewMode === 'list' ? 'grid' : viewMode === 'grid' ? 'gallery' : 'list')}
              className="p-3 bg-gray-50 text-gray-400 rounded-2xl hover:text-gray-900 transition-all font-bold text-xs flex items-center gap-2"
            >
              {viewMode === 'list' ? <List size={18}/> : viewMode === 'grid' ? <LayoutGrid size={18}/> : <ImageIcon size={18}/>}
              <span className="uppercase tracking-widest">{viewMode}</span>
            </button>
          </div>
        </header>

        {/* Selected File Action Bar */}
        {selectedFile && (
          <div className="mx-10 mt-6 p-6 rounded-[32px] bg-gradient-to-r from-blue-50 to-white border border-blue-100 flex items-center gap-8 animate-in slide-in-from-top-4 duration-500 shadow-sm">
            <div className="w-16 h-16 bg-white rounded-3xl shadow-md flex items-center justify-center">
              {getFileIcon(selectedFile.type)}
            </div>
            <div className="flex-1 min-w-0">
               <div className="flex items-center gap-3 mb-1">
                 <span className="text-[10px] font-black uppercase text-blue-600 tracking-widest px-2 py-0.5 bg-blue-100 rounded-full">{selectedFile.source} Content</span>
                 {selectedFile.source === 'google-drive' && <Cloud size={12} className="text-blue-500"/>}
                 {selectedFile.source === 'github' && <Github size={12}/>}
               </div>
               <h3 className="font-black text-xl text-gray-900 truncate">{selectedFile.name}</h3>
               <p className="text-sm text-gray-500 mt-1 line-clamp-1 italic">
                 {selectedFile.aiSummary || "Select to analyze this cloud resource..."}
               </p>
            </div>
            <div className="flex gap-3">
               <button onClick={() => openFileViewer(selectedFile)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
                 <Eye size={16}/> Open Viewer
               </button>
               <button onClick={() => setSelectedIds([])} className="p-3 bg-white text-gray-300 border border-gray-100 rounded-2xl hover:text-gray-900 transition-colors"><X size={18}/></button>
            </div>
          </div>
        )}

        {/* File Browser Area */}
        <div className="flex-1 overflow-auto p-10">
          {filteredFiles.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-40">
              <div className="w-40 h-40 bg-gray-50 rounded-full flex items-center justify-center mb-8">
                <Globe size={80} className="text-gray-100" />
              </div>
              <h2 className="text-2xl font-black text-gray-800">Empty View</h2>
              <p className="text-sm text-gray-400 mt-3 font-medium">Connect a source or upload files.</p>
            </div>
          ) : (
            <div className={`grid gap-8 ${
              viewMode === 'list' ? 'grid-cols-1' : 
              viewMode === 'gallery' ? 'grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5' :
              'grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6'
            }`}>
              {filteredFiles.map(file => (
                <div 
                  key={file.id}
                  onClick={(e) => {
                    e.stopPropagation();
                    if(e.ctrlKey || e.metaKey) setSelectedIds(prev => prev.includes(file.id) ? prev.filter(i => i !== file.id) : [...prev, file.id]);
                    else setSelectedIds([file.id]);
                  }}
                  onDoubleClick={() => file.type === FileType.FOLDER ? handleFolderClick(file) : openFileViewer(file)}
                  className={`group relative flex flex-col p-5 rounded-[32px] border transition-all cursor-pointer ${
                    selectedIds.includes(file.id) 
                    ? 'bg-blue-50 border-blue-200 ring-[8px] ring-blue-50/50 scale-105 shadow-xl' 
                    : 'bg-white border-gray-100 hover:border-gray-200 hover:shadow-lg'
                  }`}
                >
                  <div className="absolute top-4 right-4 flex gap-2">
                    {file.source === 'google-drive' && <Cloud size={14} className="text-blue-300"/>}
                    {file.source === 'github' && <Github size={14} className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity"/>}
                    {file.source === 'ai' && <Sparkles size={14} className="text-purple-400"/>}
                  </div>

                  <div className="flex-1 mb-4 rounded-[20px] flex items-center justify-center transition-transform group-hover:scale-105 overflow-hidden bg-gray-50/50 min-h-[140px]">
                    {file.type === FileType.IMAGE && file.content ? (
                      <img src={file.content} className="w-full h-full object-cover" loading="lazy" />
                    ) : (
                      React.cloneElement(getFileIcon(file.type) as React.ReactElement, { size: viewMode === 'gallery' ? 64 : 48 })
                    )}
                  </div>

                  <div className="text-center px-1">
                    <span className="text-xs font-black text-gray-900 truncate block">{file.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 uppercase tracking-widest mt-1 block">
                      {file.type === FileType.FOLDER ? 'Directory' : formatSize(file.size)}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Global Action Footer */}
        <footer className="h-28 px-10 border-t border-gray-100 bg-white/80 backdrop-blur-xl flex items-center justify-between z-10">
           <div className="flex gap-4">
             <button 
               onClick={() => fileInputRef.current?.click()}
               className="flex items-center gap-3 px-8 py-4 bg-gray-900 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all"
             >
               <FileUp size={20}/> Upload Work
             </button>
             <button onClick={() => setIsStudioOpen(true)} className="px-8 py-4 bg-purple-600 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-purple-700 active:scale-95 transition-all flex items-center gap-3">
               <Palette size={20}/> AI Studio
             </button>
           </div>

           <div className="flex items-center gap-4">
             <button className={`px-12 py-4 rounded-[24px] font-black text-xs uppercase tracking-widest transition-all ${
               selectedIds.length > 0 ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 active:scale-95' : 'bg-gray-100 text-gray-300 cursor-not-allowed'
             }`} disabled={selectedIds.length === 0}>
               PROCESS FILES
             </button>
           </div>
        </footer>
      </main>

      {/* Omni Viewer Portal */}
      {previewFile && (
        <div className="fixed inset-0 bg-gray-950/90 backdrop-blur-2xl z-[200] flex items-stretch p-12 animate-in fade-in duration-500">
           <div className="bg-white rounded-[48px] shadow-2xl w-full flex overflow-hidden border border-white/20">
              <div className="flex-1 flex flex-col min-w-0">
                <div className="h-24 px-10 border-b border-gray-100 flex items-center justify-between bg-white/50">
                  <div className="flex items-center gap-5">
                    <div className="p-3 bg-gray-50 rounded-2xl">{getFileIcon(previewFile.type)}</div>
                    <div>
                      <h2 className="font-black text-2xl text-gray-900 leading-none">{previewFile.name}</h2>
                      <div className="flex items-center gap-3 mt-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                        <span className="px-2 py-0.5 bg-gray-100 rounded-full">{previewFile.source}</span>
                        <span>{formatSize(previewFile.size)}</span>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => setPreviewFile(null)} className="p-4 bg-gray-900 text-white rounded-full hover:bg-red-600 transition-all shadow-xl active:scale-90"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-auto bg-[#f8f9fa] p-12 relative">
                  {isLoadingContent ? (
